window.PACTO.acts["dir-2005-36"]={"label": "DIRETTIVA 2005/36/CE DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Dir. 36/2005", "file": "ext-dir-2005-36.html", "external": true, "version": "consolidato 2025-10-29", "eurlex": "https://eur-lex.europa.eu/eli/dir/2005/36/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[null, "<p class=\"norm\">La presente direttiva fissa le regole con cui uno Stato membro (in seguito denominato «Stato membro ospitante»), che sul proprio territorio subordina l'accesso a una professione regolamentata o il suo esercizio al possesso di determinate qualifiche professionali, riconosce, per l'accesso alla professione e il suo esercizio, le qualifiche professionali acquisite in uno o più Stati membri (in seguito denominati «Stati membri d'origine») e che permettono al titolare di tali qualifiche di esercitarvi la stessa professione.</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<p class=\"norm\">La presente direttiva definisce altresì le regole relative all’accesso parziale a una professione regolamentata nonché al riconoscimento di tirocini professionali effettuati in un altro Stato membro.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "2": {"label": "Articolo 2", "heading": "Ambito di applicazione", "anchor": "art_2", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La presente direttiva si applica a tutti i cittadini di uno Stato membro che vogliano esercitare, come lavoratori subordinati o autonomi, compresi i liberi professionisti, una professione regolamentata in uno Stato membro diverso da quello in cui hanno acquisito le loro qualifiche professionali.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<p class=\"norm\">La presente direttiva si applica anche a tutti i cittadini di uno Stato membro che hanno effettuato un tirocinio professionale al di fuori dello Stato membro d’origine.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro può consentire, secondo norme sue proprie, ai cittadini degli Stati membri titolari di qualifiche professionali non acquisite in uno Stato membro, l'esercizio di una professione regolamentata sul proprio territorio ai sensi dell'articolo 3, paragrafo 1, lettera a). Per le professioni che rientrano nel titolo III, capo III, questo primo riconoscimento deve avvenire nel rispetto delle condizioni minime di formazione elencate in tale capo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora, per una determinata professione regolamentata, altre disposizioni specifiche direttamente relative al riconoscimento delle qualifiche professionali siano stabilite in uno strumento separato di diritto comunitario, le corrispondenti disposizioni della presente direttiva non si applicano.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La presente direttiva non si applica ai notai nominati con atto ufficiale della pubblica amministrazione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "3": {"label": "Articolo 3", "heading": "", "anchor": "art_3", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ai fini della presente direttiva si applicano le seguenti definizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«professione regolamentata»: attività, o insieme di attività professionali, l'accesso alle quali e il cui esercizio, o una delle cui modalità di esercizio, sono subordinati direttamente o indirettamente, in forza di norme legislative, regolamentari o amministrative, al possesso di determinate qualifiche professionali; in particolare costituisce una modalità di esercizio l'impiego di un titolo professionale riservato da disposizioni legislative, regolamentari o amministrative a chi possiede una specifica qualifica professionale. Quando non si applica la prima frase, è assimilata ad una professione regolamentata una professione di cui al paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«qualifiche professionali»: le qualifiche attestate da un titolo di formazione, un attestato di competenza - di cui all'articolo 11, lettera a), punto i) - e/o un'esperienza professionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«titolo di formazione»: diplomi, certificati e altri titoli rilasciati da un'autorità di uno Stato membro designata ai sensi delle disposizioni legislative, regolamentari e amministrative di tale Stato membro e che sanciscono una formazione professionale acquisita in maniera preponderante nella Comunità. Quando non si applica la prima frase, è assimilato ad un titolo di formazione un titolo di cui al paragrafo 3;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«autorità competente»: qualsiasi autorità o organismo abilitato da uno Stato membro in particolare a rilasciare o a ricevere titoli di formazione e altri documenti o informazioni, nonché a ricevere le domande e ad adottare le decisioni di cui alla presente direttiva;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«formazione regolamentata»: qualsiasi formazione specificamente orientata all'esercizio di una professione determinata e consistente in un ciclo di studi completato, eventualmente, da una formazione professionale, un tirocinio professionale o una pratica professionale.</p>\n<p class=\"list\">La struttura e il livello della formazione professionale, del tirocinio professionale o della pratica professionale sono stabiliti dalle disposizioni legislative, regolamentari o amministrative dello Stato membro in questione e sono soggetti a controllo o autorizzazione dell'autorità designata a tal fine;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M9\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«esperienza professionale»: l’esercizio effettivo e legittimo della professione in questione in uno Stato membro, a tempo pieno o a tempo parziale per un periodo equivalente;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«tirocinio di adattamento»: l'esercizio di una professione regolamentata nello Stato membro ospitante sotto la responsabilità di un professionista qualificato, accompagnato eventualmente da una formazione complementare. Il tirocinio è oggetto di una valutazione. Le modalità del tirocinio di adattamento e della sua valutazione nonché lo status di tirocinante migrante sono determinati dalle autorità competenti dello Stato membro ospitante.</p>\n<p class=\"list\">Lo status di cui il tirocinante gode nello Stato membro ospitante, soprattutto in materia di diritto di soggiorno nonché di obblighi, diritti e benefici sociali, indennità e retribuzione, è stabilito dalle autorità competenti di detto Stato membro conformemente al diritto comunitario applicabile;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M9\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«prova attitudinale»: una verifica riguardante le conoscenze, le abilità e le competenze professionali del richiedente, effettuata o riconosciuta dalle autorità competenti dello Stato membro ospitante allo scopo di valutare l’idoneità del richiedente a esercitare in tale Stato membro una professione regolamentata.</p>\n<p class=\"list\">Per consentire che la verifica sia effettuata, le autorità competenti predispongono un elenco delle materie che, in base a un confronto tra la formazione e l’istruzione richiesta nello Stato membro ospitante e quella ricevuta dal richiedente, non sono coperte dal diploma o dai titoli di formazione del richiedente.</p>\n<p class=\"list\">La prova attitudinale deve tener conto del fatto che il richiedente è un professionista qualificato nello Stato membro d’origine o di provenienza. Essa verte su materie da scegliere tra quelle che figurano nell’elenco e la cui conoscenza è essenziale per poter esercitare la professione in questione nello Stato membro ospitante. Tale prova può altresì comprendere la conoscenza delle regole professionali applicabili alle attività in questione nello Stato membro ospitante.</p>\n<p class=\"list\">Le modalità dettagliate della prova attitudinale nonché lo status di cui gode, nello Stato membro ospitante, il richiedente che desidera prepararsi alla prova attitudinale in detto Stato membro sono determinate dalle autorità competenti di detto Stato membro;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«dirigente d'azienda»: qualsiasi persona che abbia svolto in un'impresa del settore professionale corrispondente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la funzione di direttore d'azienda o di filiale, o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la funzione di institore o vice direttore d'azienda, se tale funzione implica una responsabilità corrispondente a quella dell'imprenditore o del direttore d'azienda rappresentato, o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la funzione di dirigente con mansioni commerciali e/o tecniche e responsabile di uno o più reparti dell'azienda.</p>\n</div>\n</div>\n</div>\n</div>\n<p class=\"modref\">\n▼M9\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«tirocinio professionale»: fatto salvo l’articolo 46, paragrafo 4, un periodo di pratica professionale effettuato sotto supervisione, purché costituisca una condizione per l’accesso a una professione regolamentata e che può svolgersi durante o dopo il completamento di un’istruzione che conduce a un diploma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«tessera professionale europea»: un certificato elettronico attestante o che il professionista ha soddisfatto tutte le condizioni necessarie per fornire servizi, su base temporanea e occasionale, in uno Stato membro ospitante o il riconoscimento delle qualifiche professionali ai fini dello stabilimento in uno Stato membro ospitante;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«apprendimento permanente»: l’intero complesso di istruzione generale, istruzione e formazione professionale, istruzione non formale e apprendimento informale intrapresi nel corso della vita che comporta un miglioramento delle conoscenze, delle abilità e delle competenze, che può includere l’etica professionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«motivi imperativi di interesse generale»: motivi riconosciuti tali dalla giurisprudenza della Corte di giustizia dell’Unione europea;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>n) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«Sistema europeo di accumulazione e trasferimento dei crediti o crediti ECTS»: il sistema di crediti per l’istruzione superiore utilizzato nello Spazio europeo dell’istruzione superiore.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">È assimilata a una professione regolamentata una professione esercitata dai membri di un'associazione o di un organismo di cui all'allegato I.</div>\n</div>"], [null, "<p class=\"norm\">Le associazioni o le organizzazioni di cui al primo comma hanno in particolare lo scopo di promuovere e di mantenere un livello elevato nel settore professionale in questione e a tal fine sono oggetto di un riconoscimento specifico da parte di uno Stato membro e rilasciano ai loro membri un titolo di formazione, esigono da parte loro il rispetto delle regole di condotta professionale da esse prescritte e conferiscono ai medesimi il diritto di usare un titolo o un'abbreviazione o di beneficiare di uno status corrispondente a tale titolo di formazione.</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<p class=\"norm\">Quando uno Stato membro riconosce un’associazione o un organismo di cui al primo comma, ne informa la Commissione. La Commissione esamina se tale associazione o organismo rispetta le condizioni di cui al secondo comma. Al fine di tenere debitamente conto delle evoluzioni normative negli Stati membri, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 57 <span class=\"italics\">quater</span>, al fine di aggiornare l’allegato I, qualora siano soddisfatte le condizioni di cui al secondo comma.</p>"], [null, "<p class=\"norm\">Qualora le condizioni di cui al secondo comma non siano soddisfatte, la Commissione adotta atti di esecuzione al fine di respingere la richiesta di aggiornamento dell’allegato I.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">È assimilato a un titolo di formazione ogni titolo di formazione rilasciato in un paese terzo se il suo possessore ha, nella professione in questione, un'esperienza professionale di tre anni sul territorio dello Stato membro che ha riconosciuto tale titolo ai sensi dell'articolo 2, paragrafo 2 certificata dal medesimo.</div>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Effetti del riconoscimento", "anchor": "art_4", "frags": [[null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il riconoscimento delle qualifiche professionali da parte dello Stato membro ospitante permette ai beneficiari di accedere in tale Stato membro alla stessa professione per la quale essi sono qualificati nello Stato membro d’origine e di esercitarla nello Stato membro ospitante alle stesse condizioni dei cittadini di tale Stato membro.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini della presente direttiva, la professione che l'interessato intende esercitare nello Stato membro ospitante sarà quella per la quale è qualificato nel proprio Stato membro d'origine, se le attività coperte sono comparabili.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 1, l’accesso parziale a una professione nello Stato membro ospitante è garantito alle condizioni stabilite all’articolo 4 <span class=\"italics\">septies</span>.</div>\n</div>"]]}, "4a": {"label": "Articolo 4 bis", "heading": "Tessera professionale europea", "anchor": "art_4a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri sono tenuti a rilasciare una tessera professionale europea ai titolari di una qualifica professionale, su richiesta degli stessi e a condizione che la Commissione abbia adottato i relativi atti di esecuzione di cui al paragrafo 7.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora sia stata introdotta una tessera professionale europea per una particolare professione mediante gli atti di esecuzione pertinenti adottati a norma del paragrafo 7, il titolare della qualifica professionale in questione può scegliere di presentare domanda per tale tessera o ricorrere alle procedure di cui ai titoli II e III.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri sono tenuti a garantire che il titolare di una tessera professionale europea benefici di tutti i diritti conferiti dagli articoli da 4 <span class=\"italics\">ter</span> a 4 <span class=\"italics\">sexies</span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Nel caso in cui il titolare di una qualifica professionale intenda prestare a norma del titolo II servizi diversi da quelli contemplati all’articolo 7, paragrafo 4, l’autorità competente dello Stato membro d’origine rilascia la tessera professionale europea conformemente agli articoli 4 <span class=\"italics\">ter</span> e 4 <span class=\"italics\">quater</span>. La tessera professionale europea costituisce, ove applicabile, la dichiarazione di cui all’articolo 7.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualora il titolare di una qualifica professionale intenda stabilirsi in un altro Stato membro a norma del titolo III, capi da I a III bis, o fornire servizi a norma dell’articolo 7, paragrafo 4, l’autorità competente dello Stato membro d’origine completa tutte le fasi preparatorie concernenti il fascicolo personale del richiedente creato nell’ambito del sistema di informazione del mercato interno (IMI) (fascicolo IMI) di cui agli articoli 4 <span class=\"italics\">ter</span> e 4 <span class=\"italics\">quinquies</span>. L’autorità competente dello Stato membro ospitante rilascia la tessera professionale europea conformemente agli articoli 4 <span class=\"italics\">ter</span> e 4 <span class=\"italics\">quinquies</span>.</div>\n</div>"], [null, "<p class=\"norm\">Ai fini dello stabilimento, il rilascio della tessera professionale europea non conferisce un diritto automatico all’esercizio di una particolare professione se esistono requisiti di registrazione o altre procedure di controllo già vigenti nello Stato membro ospitante prima dell’introduzione della tessera professionale europea per quella professione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli Stati membri designano le autorità competenti per la gestione dei fascicoli IMI e il rilascio delle tessere professionali europee. Dette autorità sono tenute a garantire un trattamento imparziale, obiettivo e tempestivo delle domande di tessera professionale europea. I centri di assistenza di cui all’articolo 57 <span class=\"italics\">ter</span> possono anche agire come autorità competenti. Gli Stati membri sono tenuti a garantire che le autorità competenti e i centri di assistenza informino i cittadini, inclusi i potenziali richiedenti, in merito al funzionamento e al valore aggiunto di una tessera professionale europea, in relazione alle professioni per le quali essa è disponibile.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">La Commissione adotta, mediante atti di esecuzione, misure necessarie a garantire l’applicazione uniforme delle disposizioni riguardanti le tessere professionali europee per quelle professioni che soddisfano le condizioni di cui al secondo comma del presente paragrafo, incluse le misure relative al formato di tali tessere, il trattamento delle domande scritte, le traduzioni che il richiedente deve fornire a supporto di ogni richiesta di una tessera professionale europea, i dettagli relativi ai documenti richiesti a norma dell’articolo 7, paragrafo 2, o dell’allegato VII per presentare una domanda completa e le procedure di pagamento e di trattamento dei pagamenti in relazione a tale tessera, tenendo presente le specificità della professione interessata. La Commissione specifica inoltre mediante atti di esecuzione le norme che stabiliscono come, quando e per quale tipo di documenti le autorità competenti possono chiedere copie certificate, conformemente all’articolo 4 <span class=\"italics\">ter</span>, paragrafo 3, secondo comma, e all’articolo 4 <span class=\"italics\">quinquies</span>, paragrafi 2 e 3, per la professione interessata.</div>\n</div>"], [null, "<p class=\"norm inline-element\">L’introduzione di una tessera professionale europea per una determinata professione, mediante l’adozione di atti di esecuzione pertinenti a norma del primo comma, è soggetta alle seguenti condizioni:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esistenza di una significativa mobilità, o una significativa potenziale mobilità, nella professione interessata;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esistenza di un sufficiente interesse manifestato dalle parti interessate;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la professione o l’istruzione e la formazione che portano all’esercizio della professione sono regolamentate in un numero significativo di Stati membri.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 58, paragrafo 2.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Tutti gli oneri a carico dei richiedenti in relazione a procedure amministrative connesse al rilascio della tessera professionale europea devono essere ragionevoli, proporzionati e commisurati ai costi sostenuti dagli Stati membri d’origine e ospitanti e non devono dissuadere dal richiedere una tessera professionale europea.</div>\n</div>"]]}, "4b": {"label": "Articolo 4 ter", "heading": "Domanda di tessera professionale europea e creazione di un fascicolo IMI", "anchor": "art_4b", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Lo Stato membro d’origine consente al titolare di una qualifica professionale di richiedere il rilascio di una tessera professionale europea mediante uno strumento online, fornito dalla Commissione, che crea automaticamente un fascicolo IMI per il singolo richiedente. Qualora uno Stato membro d’origine consenta anche di presentare domande scritte, predispone tutte le misure necessarie per la creazione del fascicolo IMI, per l’invio di tutte le informazioni necessarie al richiedente e per il rilascio della tessera professionale europea.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le domande sono corredate dei documenti richiesti negli atti di esecuzione adottati a norma dell’articolo 4 <span class=\"italics\">bis</span>, paragrafo 7.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Entro una settimana dal ricevimento della domanda, l’autorità competente dello Stato membro d’origine accusa ricezione della domanda e informa il richiedente di eventuali documenti mancanti.</div>\n</div>"], [null, "<p class=\"norm\">Se del caso, l’autorità competente dello Stato membro d’origine rilascia ogni certificato di supporto, richiesto sulla base della presente direttiva. L’autorità competente dello Stato membro d’origine verifica che il richiedente sia legalmente stabilito in tale Stato nonché l’autenticità e la validità di tutti i documenti necessari rilasciati dallo Stato stesso. In caso di dubbi debitamente giustificati, l’autorità competente dello Stato membro d’origine consulta l’organismo competente e può chiedere al richiedente copie certificate dei documenti. Se il medesimo richiedente presenta ulteriori domande, le autorità competenti degli Stati membri d’origine e ospitanti non possono chiedere nuovamente la presentazione dei documenti già inclusi nel fascicolo IMI e ancora validi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione può adottare, mediante atti di esecuzione, le specifiche tecniche, le misure necessarie per garantire l’integrità, la riservatezza e l’accuratezza delle informazioni contenute nella tessera professionale europea e nel fascicolo IMI, e le condizioni e le procedure per rilasciare al titolare la tessera stessa, inclusa la possibilità di scaricarla o di produrre aggiornamenti per il fascicolo IMI. Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 58, paragrafo 2.</div>\n</div>"]]}, "4c": {"label": "Articolo 4 quater", "heading": "Tessera professionale europea per la prestazione temporanea e occasionale di servizi diversi da quelli previsti all’articolo 7, paragrafo 4", "anchor": "art_4c", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’autorità competente dello Stato membro d’origine è tenuta a verificare la domanda e i documenti giustificativi nel fascicolo IMI e a rilasciare la tessera professionale europea per la prestazione temporanea e occasionale di servizi diversi da quelli previsti all’articolo 7, paragrafo 4, entro tre settimane. Il periodo decorre dal ricevimento dei documenti mancanti di cui all’articolo 4 <span class=\"italics\">ter</span>, paragrafo 3, primo comma, oppure, se non sono stati richiesti ulteriori documenti, alla scadenza del periodo di una settimana previsto in tale comma. Essa quindi trasmette immediatamente la tessera professionale europea all’autorità competente di ciascuno Stato membro ospitante interessato e ne informa di conseguenza il richiedente. Lo Stato membro ospitante non può richiedere nessuna ulteriore dichiarazione di cui all’articolo 7 per i successivi diciotto mesi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La decisione dell’autorità competente dello Stato membro d’origine, oppure l’assenza di decisione entro il termine di tre settimane di cui al paragrafo 1, è soggetto a ricorso in base al diritto interno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il titolare di una tessera professionale europea, che intenda prestare servizi in Stati membri diversi da quelli menzionati inizialmente nella domanda di cui al paragrafo 1, può fare domanda per tale estensione. Qualora il titolare intenda continuare a prestare i servizi oltre il periodo di diciotto mesi indicato nel paragrafo 1, ne informa di conseguenza l’autorità competente. In entrambi i casi, il titolare fornisce anche tutte le informazioni relative a mutamenti oggettivi della situazione comprovata nel fascicolo IMI che potrebbero essere richieste dall’autorità competente dello Stato membro d’origine conformemente agli atti di esecuzione adottati a norma dell’articolo 4 <span class=\"italics\">bis</span>, paragrafo 7. L’autorità competente dello Stato membro d’origine trasmette la tessera professionale europea aggiornata agli Stati membri ospitanti interessati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La tessera professionale europea è valida sull’intero territorio di tutti gli Stati membri ospitanti interessati per tutto il tempo in cui il rispettivo titolare conserva il diritto di esercitare, sulla base dei documenti e delle informazioni contenute nel fascicolo IMI.</div>\n</div>"]]}, "4d": {"label": "Articolo 4 quinquies", "heading": "Tessera professionale europea per lo stabilimento e la prestazione temporanea e occasionale di servizi a norma dell’articolo 7, paragrafo 4", "anchor": "art_4d", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’autorità competente dello Stato membro d’origine è tenuta a verificare entro un mese l’autenticità e la validità dei documenti giustificativi nel fascicolo IMI ai fini del rilascio di una tessera professionale europea per lo stabilimento o la prestazione temporanea e occasionale di servizi a norma dell’articolo 7, paragrafo 4. Il periodo decorre dal ricevimento dei documenti mancanti di cui all’articolo 4 <span class=\"italics\">ter</span>, paragrafo 3, primo comma oppure, se non sono stati richiesti ulteriori documenti, alla scadenza del termine di una settimana previsto in tale comma. Essa trasmette poi immediatamente la domanda all’autorità competente dello Stato membro ospitante. Lo Stato membro d’origine informa il richiedente in merito allo stato della domanda nel momento in cui la trasmette allo Stato membro ospitante.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi previsti agli articoli 16, 21, 49 <span class=\"italics\">bis</span> e 49 <span class=\"italics\">ter</span>, lo Stato membro ospitante decide se rilasciare una tessera professionale europea ai sensi del paragrafo 1 entro un mese a decorrere dalla data di ricevimento della domanda trasmessa dallo Stato membro d’origine. In caso di dubbi debitamente giustificati, lo Stato membro ospitante può chiedere ulteriori informazioni allo Stato membro d’origine o l’inclusione della copia certificata di un documento da parte dello Stato membro d’origine, che quest’ultimo è tenuto a presentare non oltre due settimane dalla presentazione della richiesta. Fatto salvo il paragrafo 5, secondo comma, si applica il periodo di un mese, nonostante eventuali domande di questo tipo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nei casi previsti all’articolo 7, paragrafo 4, e all’articolo 14, lo Stato membro ospitante decide, entro due mesi dal ricevimento della domanda trasmessa dallo Stato membro d’origine, se intende rilasciare una tessera professionale europea oppure se assoggettare il titolare di una qualifica professionale a misure compensative. In caso di dubbi debitamente giustificati, lo Stato membro ospitante può chiedere ulteriori informazioni allo Stato membro d’origine o l’inclusione della copia certificata di un documento da parte dello Stato membro d’origine, che quest’ultimo è tenuto a presentare non oltre due settimane dalla presentazione della domanda. Fatto salvo il paragrafo 5, secondo comma, si applica il periodo di due mesi, nonostante eventuali domande di questo tipo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Nel caso in cui lo Stato membro ospitante non riceva, da parte dello Stato membro d’origine o del richiedente, le informazioni necessarie, che può richiedere conformemente alla presente direttiva per decidere in merito al rilascio della tessera professionale europea, può rifiutarsi di rilasciare la tessera. Tale rifiuto è debitamente giustificato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualora uno Stato membro ospitante non adotti una decisione entro il termine stabilito ai paragrafi 2 e 3 del presente articolo o non organizzi una prova attitudinale conformemente all’articolo 7, paragrafo 4, la tessera professionale europea si considera rilasciata ed è inviata automaticamente, mediante il sistema IMI, al titolare di una qualifica professionale.</div>\n</div>"], [null, "<p class=\"norm\">Lo Stato membro ospitante ha la possibilità di estendere di due settimane il termine di cui ai paragrafi 2 e 3 per il rilascio automatico della tessera professionale europea. Esso spiega le ragioni della proroga e ne informa il richiedente. Tale proroga può essere ripetuta una volta sola e unicamente quando essa è strettamente necessaria, in particolare per ragioni relative alla salute pubblica o alla sicurezza dei destinatari del servizio.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le misure intraprese dallo Stato membro di origine conformemente al paragrafo 1 sostituiscono qualsivoglia domanda di riconoscimento di qualifiche professionali ai sensi della legislazione nazionale dello Stato membro ospitante.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Le decisioni degli Stati membri d’origine e ospitante adottate ai sensi dei paragrafi da 1 a 5 oppure l’assenza di una qualsivoglia decisione da parte dello Stato membro d’origine sono soggette a un ricorso in base al diritto interno dello Stato membro interessato.</div>\n</div>"]]}, "4e": {"label": "Articolo 4 sexies", "heading": "Elaborazione e accesso ai dati riguardanti la tessera professionale europea", "anchor": "art_4e", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatta salva la presunzione di innocenza, le autorità competenti degli Stati membri d’origine e ospitante aggiornano tempestivamente il corrispondente fascicolo IMI con le informazioni riguardanti le azioni disciplinari o le sanzioni penali relative a un divieto o una restrizione e che hanno conseguenze sull’esercizio delle attività da parte del titolare di una tessera professionale europea ai sensi della presente direttiva. Nel compiere tale attività esse rispettano le norme sulla protezione dei dati personali stabilite dalla direttiva 95/46/CE del Parlamento europeo e del Consiglio, del 24 ottobre 1995, relativa alla tutela delle persone fisiche con riguardo al trattamento dei dati personali, nonché alla libera circolazione di tali dati (\n<span class=\"superscript\">1</span>\n), e dalla direttiva 2002/58/CE del Parlamento europeo e del Consiglio, del 12 luglio 2002, relativa al trattamento dei dati personali e alla tutela della vita privata nel settore delle comunicazioni elettroniche (direttiva relativa alla vita privata e alle comunicazioni elettroniche) (\n<span class=\"superscript\">2</span>\n). Tali aggiornamenti includono la soppressione di informazioni che non sono più richieste. Il titolare della tessera professionale europea e le autorità competenti che hanno accesso al corrispondente fascicolo IMI devono essere informate immediatamente di ogni aggiornamento. Tale obbligo lascia impregiudicati gli obblighi di allerta a carico degli Stati membri di cui all’articolo 56 <span class=\"italics\">bis</span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il contenuto degli aggiornamenti delle informazioni di cui al paragrafo 1 si limita a indicare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’identità del professionista;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la professione interessata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni riguardanti l’autorità o il tribunale nazionale che ha adottato la decisione di divieto o restrizione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’ambito di applicazione della restrizione o del divieto; nonché</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il periodo nel quale si applica la restrizione o il divieto.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’accesso alle informazioni contenute nel fascicolo IMI è limitato alle autorità competenti degli Stati membri d’origine e ospitanti conformemente alla direttiva 95/46/CE. Le autorità competenti informano il titolare della tessera professionale europea, su richiesta di quest’ultimo, in merito al contenuto del fascicolo IMI.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le informazioni contenute nella tessera professionale europea si limitano alle informazioni necessarie per accertare il diritto del titolare all’esercizio della professione per la quale la tessera è stata rilasciata, vale a dire nome, cognome, data e luogo di nascita, professione, qualifiche formali del titolare e regime applicabile, autorità competenti coinvolte, numero di tessera, caratteristiche di sicurezza e riferimento a un documento di identità valido. Le informazioni relative all’esperienza professionale acquisita dal titolare della tessera professionale europea, o le misure compensative superate, sono incluse nel fascicolo IMI.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I dati personali inclusi nel fascicolo IMI possono essere trattati per tutto il tempo necessario ai fini della procedura di riconoscimento in quanto tale e come prova del riconoscimento o della trasmissione della dichiarazione prevista all’articolo 7. Gli Stati membri assicurano che il titolare della tessera professionale europea abbia il diritto di chiedere, in qualsivoglia momento e senza costi, la rettifica di dati inesatti o incompleti, oppure la soppressione o il blocco del fascicolo IMI interessato. Il titolare è informato di tale diritto al momento del rilascio della tessera professionale europea e gli si ricorda tale diritto ogni due anni dopo il rilascio della tessera. Qualora la domanda iniziale di tessera professionale europea sia presentata online, tale promemoria è inviato automaticamente mediante il sistema IMI.</div>\n</div>"], [null, "<p class=\"norm\">In caso di richiesta di soppressione di un fascicolo IMI collegato a una tessera professionale europea rilasciata per lo stabilimento o la prestazione temporanea e occasionale di servizi a norma dell’articolo 7, paragrafo 4, le autorità competenti dello Stato membro ospitante interessato rilasciano al titolare di qualifiche professionali un attestato di riconoscimento delle proprie qualifiche professionali.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Con riguardo all’elaborazione di dati personali contenuti nella tessera professionale europea e in tutti i fascicoli IMI, le autorità competenti degli Stati membri sono considerate autorità di controllo ai sensi dell’articolo 2, lettera d),della direttiva 95/46/CE. In relazione alle responsabilità che a essa incombono a norma dei paragrafi da 1 a 4 del presente articolo e all’elaborazione dei dati personali ivi contemplati, la Commissione è considerata un’autorità di controllo ai sensi dell’articolo 2, lettera d), del regolamento (CE) n. 45/2001 del Parlamento europeo e del Consiglio, del 18 dicembre 2000, concernente la tutela delle persone fisiche in relazione al trattamento dei dati personali da parte delle istituzioni e degli organismi comunitari, nonché la libera circolazione di tali dati (\n<span class=\"superscript\">3</span>\n).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Fatto salvo il paragrafo 3, gli Stati membri ospitanti prevedono la possibilità per datori di lavoro, consumatori, pazienti, autorità pubbliche e altre parti interessate di verificare l’autenticità e la validità di una tessera professionale europea presentata loro dal titolare della stessa.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione stabilisce, mediante atti di esecuzione, le norme in materia di accesso al fascicolo IMI e i mezzi tecnici e le procedure di verifica di cui al primo comma. Gli atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 58, paragrafo 2.</p>"]]}, "4f": {"label": "Articolo 4 septies", "heading": "Accesso parziale", "anchor": "art_4f", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’autorità competente dello Stato membro ospitante accorda l’accesso parziale, previa valutazione di ciascun singolo caso, a un’attività professionale sul proprio territorio unicamente se sono soddisfatte tutte le seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il professionista è pienamente qualificato per esercitare nello Stato membro d’origine l’attività professionale per la quale si chiede un accesso parziale nello Stato membro ospitante;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le differenze tra l’attività professionale legalmente esercitata nello Stato membro d’origine e la professione regolamentata nello Stato membro ospitante sono così rilevanti che l’applicazione di misure compensative comporterebbe per il richiedente di portare a termine il programma completo di istruzione e formazione previsto dallo Stato membro ospitante al fine di avere accesso all’intera professione regolamentata in detto Stato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attività professionale può essere oggettivamente separata da altre attività che rientrano nella professione regolamentata dello Stato membro ospitante.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Ai fini della lettera c), l’autorità competente dello Stato membro ospitante prende in considerazione se l’attività professionale può essere esercitata autonomamente nello Stato membro d’origine.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’accesso parziale può essere rifiutato se ciò è giustificato da un motivo imperativo di interesse generale, che permette di conseguire l’obiettivo perseguito e si limita a quanto necessario per raggiungere tale obiettivo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le domande ai fini dello stabilimento in uno Stato membro ospitante sono esaminate conformemente al titolo III, capi I e IV.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le domande ai fini della prestazione di servizi temporanei e occasionali nello Stato membro ospitante, concernenti attività professionali che hanno implicazioni a livello di salute pubblica o di sicurezza, sono oggetto di esame conformemente al titolo II.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 7, paragrafo 4, sesto comma, e all’articolo 52, paragrafo 1, l’attività professionale è esercitata con il titolo professionale dello Stato membro d’origine una volta accordato l’accesso parziale. Lo Stato membro ospitante può richiedere che tale titolo professionale sia utilizzato nelle lingue di tale Stato membro. I professionisti che beneficiano dell’accesso parziale indicano chiaramente ai destinatari del servizio l’ambito delle proprie attività professionali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il presente articolo non si applica ai professionisti che beneficiano del riconoscimento automatico delle qualifiche professionali a norma del titolo III, capi II, III e III bis.</div>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "Principio di libera prestazione di servizi", "anchor": "art_5", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fatte salve le disposizioni specifiche del diritto comunitario e gli articoli 6 e 7 della presente direttiva, gli Stati membri non possono limitare, per ragioni attinenti alle qualifiche professionali, la libera prestazione di servizi in un altro Stato membro:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il prestatore è legalmente stabilito in uno Stato membro per esercitarvi la stessa professione (in seguito denominato «Stato membro di stabilimento»), e</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M9\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di spostamento del prestatore, se questi ha esercitato tale professione in uno o più Stati membri per almeno un anno nel corso dei dieci anni che precedono la prestazione di servizi, se la professione non è regolamentata nello Stato membro di stabilimento. La condizione che esige un anno di esercizio della professione non si applica se la professione o la formazione che porta alla professione è regolamentata.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le disposizioni del presente titolo si applicano esclusivamente nel caso in cui il prestatore si sposta sul territorio dello Stato membro ospitante per esercitare, in modo temporaneo e occasionale, la professione di cui al paragrafo 1.</div>\n</div>"], [null, "<p class=\"norm\">Il carattere temporaneo e occasionale della prestazione è valutato caso per caso, in particolare in funzione della durata della prestazione stessa, della sua frequenza, della sua periodicità e della sua continuità.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In caso di spostamento, il prestatore è soggetto a norme professionali, di carattere professionale, legale o amministrativo, direttamente connesse alle qualifiche professionali, quali la definizione della professione, l'uso dei titoli e gravi errori professionali connessi direttamente e specificamente alla tutela e sicurezza dei consumatori, nonché le disposizioni disciplinari applicabili nello Stato membro ospitante ai professionisti che, ivi, esercitano la stessa professione.</div>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Esenzioni", "anchor": "art_6", "frags": [[null, "<p class=\"norm\">Ai sensi dell'articolo 5, paragrafo 1, lo Stato membro ospitante dispensa i prestatori di servizi stabiliti in un altro Stato membro dai requisiti imposti ai professionisti stabiliti sul suo territorio e riguardanti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'autorizzazione, l'iscrizione o l'adesione a un'organizzazione o a un organismo professionale. Per facilitare l'applicazione di disposizioni disciplinari in vigore nel loro territorio, a norma dell'articolo 5, paragrafo 3, gli Stati membri possono prevedere un'iscrizione temporanea e automatica o un'adesione pro forma a tale organizzazione o organismo professionale, purché tale iscrizione o adesione non ritardi né complichi in alcun modo la prestazione di servizi e non comporti oneri supplementari per il prestatore di servizi. Una copia della dichiarazione e, se del caso, della proroga di cui all'articolo 7, paragrafo 1, corredata, per le professioni aventi ripercussioni in materia di pubblica sicurezza e di sanità pubblica ai sensi dell'articolo 7, paragrafo 4 o riconosciute automaticamente in virtù del titolo VII, capo III, di una copia dei documenti di cui all'articolo 7, paragrafo 2, è inviata dall'autorità competente alla pertinente organizzazione o organismo professionale e questa costituisce un'iscrizione temporanea e automatica o un'adesione pro forma a tal fine,</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'iscrizione a un ente di previdenza sociale di diritto pubblico, per regolare con un ente assicuratore i conti relativi alle attività esercitate a profitto degli assicurati sociali.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Tuttavia il prestatore di servizi informa in anticipo o, in caso di urgenza, successivamente, l'ente di cui alla lettera b), della sua prestazione di servizi.</p>"]]}, "7": {"label": "Articolo 7", "heading": "Dichiarazione preventiva in caso di spostamento del prestatore", "anchor": "art_7", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono esigere che, se il prestatore si sposta per la prima volta da uno Stato membro all'altro per fornire servizi, questi informi in anticipo l'autorità competente dello Stato membro ospitante con una dichiarazione scritta contenente informazioni sulla copertura assicurativa o analoghi mezzi di protezione personale o collettiva per la responsabilità professionale. Tale dichiarazione è rinnovata annualmente se il prestatore intende fornire servizi temporanei o occasionali in tale Stato membro durante l'anno in questione. Il prestatore può fornire la dichiarazione con qualsiasi mezzo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Inoltre, per la prima prestazione di servizi o in caso di mutamento oggettivo della situazione comprovata dai documenti, gli Stati membri possono richiedere che la dichiarazione sia corredata dei seguenti documenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una prova della nazionalità del prestatore,</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un attestato che certifichi che il titolare è legalmente stabilito in uno Stato membro per esercitare le attività in questione e che non gli è vietato esercitarle, anche su base temporanea, al momento del rilascio dell'attestato,</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una prova dei titoli di qualifiche professionali,</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M9\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nei casi di cui all’articolo 5, paragrafo 1, lettera b), una prova con qualsiasi mezzo che il prestatore ha esercitato l’attività in questione per almeno un anno nel corso dei dieci anni che precedono la prestazione di servizi,</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le professioni nel settore della sicurezza, nel settore della sanità e per le professioni inerenti all’istruzione dei minori, inclusa l’assistenza e l’istruzione della prima infanzia, qualora lo Stato membro lo richieda per i propri cittadini, un attestato che confermi l’assenza di sospensioni temporanee o definitive dall’esercizio della professione o di condanne penali,</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M9\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le professioni che hanno implicazioni per la sicurezza dei pazienti, una dichiarazione della conoscenza, da parte del richiedente, della lingua necessaria all’esercizio della professione nello Stato membro ospitante,</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le professioni riguardanti le attività di cui all’articolo 16 e che sono state notificate da uno Stato membro conformemente all’articolo 59, paragrafo 2, un certificato concernente la natura e la durata dell’attività, rilasciato dall’autorità o dall’organismo competente dello Stato membro in cui il fornitore dei servizi è stabilito.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La presentazione della richiesta dichiarazione da parte del prestatore conformemente al paragrafo 1 consente a tale prestatore di servizi di avere accesso all’attività di servizio o di esercitarla sull’intero territorio dello Stato membro interessato. Uno Stato membro può richiedere le informazioni supplementari elencate al paragrafo 2, per quanto concerne le qualifiche professionali del fornitore di servizi se:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la professione è regolamentata in modo diverso in parti del territorio di tale Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tale regolamentazione è applicabile anche a tutti i cittadini di tale Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le differenze in tale regolamentazione sono giustificate da motivi imperativi di interesse generale relative alla salute pubblica o alla sicurezza dei destinatari del servizio; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro non può ottenere diversamente tali informazioni.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La prestazione è effettuata con il titolo professionale dello Stato membro di stabilimento allorché un siffatto titolo regolamentato esista in detto Stato membro per l'attività professionale di cui trattasi. Questo titolo è indicato nella lingua ufficiale o in una delle lingue ufficiali dello Stato membro di stabilimento onde evitare confusioni con il titolo professionale dello Stato membro ospitante. Nei casi in cui il suddetto titolo professionale non esista nello Stato membro di stabilimento il prestatore indica il suo titolo di formazione nella lingua ufficiale o in una delle lingue ufficiali di detto Stato membro. In via eccezionale la prestazione è effettuata con il titolo professionale dello Stato membro ospitante per i casi di cui al titolo III, capo III.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">All’atto della prima prestazione di servizi, nel caso delle professioni regolamentate aventi ripercussioni in materia di pubblica sicurezza o di sanità pubblica, che non beneficiano del riconoscimento automatico ai sensi del titolo III, capo II, III o III bis, l’autorità competente dello Stato membro ospitante può procedere a una verifica delle qualifiche professionali del prestatore prima della prima prestazione di servizi. Questa verifica preventiva è possibile unicamente se è finalizzata a evitare danni gravi per la salute o la sicurezza del destinatario del servizio per la mancanza di qualifica professionale del prestatore e non va oltre quanto è necessario a tal fine.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Non oltre un mese dopo la ricezione della dichiarazione e dei documenti che la corredano, di cui ai paragrafi 1 e 2, l’autorità competente informa il prestatore della sua decisione:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">di non procedere alla verifica delle sue qualifiche professionali;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">previa verifica delle sue qualifiche professionali:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">di esigere dal prestatore una prova attitudinale; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">di consentire la prestazione dei servizi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Qualora vi sia una difficoltà che causi un ritardo nell’adottare la decisione di cui al secondo comma, l’autorità competente notifica entro lo stesso termine al prestatore il motivo del ritardo. La difficoltà è risolta entro un mese dalla notifica e la decisione è presa non più tardi dei due mesi successivi alla risoluzione della difficoltà.</p>"], [null, "<p class=\"norm\">In caso di differenze sostanziali tra le qualifiche professionali del prestatore e la formazione richiesta nello Stato membro ospitante, nella misura in cui tale differenza sia tale da nuocere alla salute pubblica o alla sicurezza e non possa essere compensata dall’esperienza professionale del prestatore o da conoscenze, abilità e competenze acquisite attraverso l’apprendimento permanente, formalmente convalidate a tal fine da un organismo competente, lo Stato membro ospitante è tenuto a offrire al prestatore la possibilità di dimostrare, mediante una prova attitudinale di cui alla lettera b) del secondo comma, di avere acquisito le conoscenze, le abilità o le competenze mancanti. Su tale base lo Stato membro ospitante decide se consentire la prestazione di servizi. A ogni modo, la prestazione di servizi deve poter essere effettuata entro un mese dalla decisione adottata in applicazione del secondo comma.</p>"], [null, "<p class=\"norm\">In mancanza di reazioni da parte dell’autorità competente entro il termine fissato al secondo e al terzo comma, la prestazione di servizi può essere effettuata.</p>"], [null, "<p class=\"norm\">Nei casi in cui le qualifiche professionali sono state verificate ai sensi del presente paragrafo, la prestazione di servizi è effettuata con il titolo professionale dello Stato membro ospitante.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "8": {"label": "Articolo 8", "heading": "Cooperazione amministrativa", "anchor": "art_8", "frags": [[null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le autorità competenti dello Stato membro ospitante possono chiedere alle autorità competenti dello Stato membro di stabilimento, ove sussistano giustificati dubbi, di fornire qualsivoglia informazione pertinente circa la legalità dello stabilimento del prestatore e la sua buona condotta del prestatore nonché l’assenza di sanzioni disciplinari o penali di natura professionale. Qualora decidano di procedere alla verifica delle qualifiche professionali del prestatore, le autorità competenti dello Stato membro ospitante possono chiedere informazioni circa i corsi di formazione seguiti dal prestatore alle competenti autorità dello Stato membro di stabilimento, nella misura necessaria per la valutazione delle differenze sostanziali potenzialmente pregiudizievoli per la sicurezza o la sanità pubblica. Le autorità competenti dello Stato membro di stabilimento forniscono dette informazioni conformemente all’articolo 56. Nel caso delle professioni non regolamentate nello Stato membro d’origine, anche i centri assistenza di cui all’articolo 57 <span class=\"italics\">ter</span> possono fornire anche tali informazioni.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le autorità competenti provvedono affinché lo scambio di tutte le informazioni necessarie per un reclamo del destinatario di un servizio contro un prestatore avvenga correttamente. I destinatari sono informati dell'esito del reclamo.</div>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Informazione ai destinatari del servizio", "anchor": "art_9", "frags": [[null, "<p class=\"norm\">Nei casi in cui la prestazione è effettuata con il titolo professionale dello Stato membro di stabilimento o con il titolo di formazione del prestatore, oltre alle altre informazioni previste dal diritto comunitario, le autorità competenti dello Stato membro ospitante possono richiedere al prestatore di fornire al destinatario del servizio alcune o tutte le seguenti informazioni:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il prestatore è iscritto in un registro commerciale o in un analogo registro pubblico, il registro in cui è iscritto, il suo numero d'iscrizione o un mezzo d'identificazione equivalente, che appaia in tale registro;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se l'attività è sottoposta a un regime di autorizzazione nello Stato membro di stabilimento, gli estremi della competente autorità di vigilanza;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'ordine professionale, o analogo organismo, presso cui il prestatore è iscritto;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il titolo professionale o, ove il titolo non esista, il titolo di formazione del prestatore, e lo Stato membro in cui è stato conseguito;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il prestatore esercita un'attività soggetta all'IVA, il numero d'identificazione IVA di cui all'articolo 22, paragrafo 1, della direttiva 77/388/CEE del Consiglio, del 17 maggio 1977, in materia di armonizzazione delle legislazioni degli Stati membri relative alle imposte sulla cifra d'affari. Sistema comune d'imposta sul valore aggiunto: base imponibile uniforme (\n<span class=\"superscript\">4</span>\n);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le prove di qualsiasi copertura assicurativa o analoghi mezzi di tutela personale o collettiva per la responsabilità professionale.</p>\n</div>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Ambito di applicazione", "anchor": "art_10", "frags": [[null, "<p class=\"norm\">Il presente capo si applica a tutte le professioni non coperte dai capi II e III del presente titolo e nei seguenti casi in cui i richiedenti, per una ragione specifica ed eccezionale, non soddisfano le condizioni previste in detti capi:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le attività elencate all'allegato IV, qualora il migrante non soddisfi i requisiti di cui agli articoli 17, 18 e 19;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M16\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i medici con formazione di base, i medici specialisti, gli infermieri responsabili dell’assistenza generale, i dentisti, i dentisti specialisti, i veterinari, le ostetriche, i farmacisti e gli architetti, qualora il migrante non soddisfi i requisiti di pratica professionale effettiva e lecita previsti agli articoli 23, 27, 33, 33 <span class=\"italics\">bis</span>, 37, 39, 43 e 49;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per gli architetti, qualora il migrante sia in possesso di un titolo di formazione non elencato all'allegato V, punto 5.7;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<span>\n<span class=\"boldface\">►C2</span>\n</span> <p class=\"norm\">fatti salvi gli articoli 21, paragrafo 1, 23 e 27 per i medici, gli infermieri, i dentisti, i veterinari, le ostetriche, i farmacisti e gli architetti in possesso di titoli di formazione specialistica, che devono aver seguito la formazione che porta al possesso dei titoli<span class=\"boldface\"> ◄ </span> elencati all'allegato V, punti 5.1.1, 5.2.2, 5.3.2, 5.4.2, 5.5.2, 5.6.2 e 5.7.1, e solamente ai fini del riconoscimento della pertinente specializzazione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<span>\n<span class=\"boldface\">►C2</span>\n</span> <p class=\"norm\">per gli infermieri responsabili dell'assistenza generale e per gli infermieri specializzati in possesso di titoli di formazione specialistica, che hanno seguito la formazione che porta al possesso dei titoli<span class=\"boldface\"> ◄ </span> elencati all'allegato V, punto 5.2.2, qualora il migrante chieda il riconoscimento in un altro Stato membro in cui le pertinenti attività professionali sono esercitate da infermieri specializzati sprovvisti della formazione di infermiere responsabile dell'assistenza generale;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼C2\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per gli infermieri specializzati sprovvisti della formazione di infermiere responsabile dell'assistenza generale, qualora il migrante chieda il riconoscimento in un altro Stato membro in cui le pertinenti attività professionali sono esercitate da infermieri responsabili dell'assistenza generale, da infermieri specializzati sprovvisti della formazione di infermiere responsabile dell'assistenza generale o da infermieri specializzati in possesso di titoli di formazione specialistica, che hanno seguito la formazione che porta al possesso dei titoli elencati all'allegato V, punto 5.2.2;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i migranti in possesso dei requisiti previsti all'articolo 3, paragrafo 3.</p>\n</div>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Livelli di qualifica", "anchor": "art_11", "frags": [[null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<p class=\"norm\">Ai fini dell’articolo 13 e dell’articolo 14, paragrafo 6, le qualifiche professionali sono raggruppate nei seguenti livelli:</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un attestato di competenza rilasciato da un'autorità competente dello Stato membro d'origine designata ai sensi delle disposizioni legislative, regolamentari o amministrative di tale Stato membro, sulla base:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">o di una formazione non facente parte di un certificato o diploma ai sensi delle lettere b), c), d) o e), o di un esame specifico non preceduto da una formazione o dell'esercizio a tempo pieno della professione per tre anni consecutivi in uno Stato membro o a tempo parziale per un periodo equivalente nei precedenti dieci anni,</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">o di una formazione generale a livello d'insegnamento elementare o secondario attestante che il titolare possiede conoscenze generali;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un certificato che attesta il compimento di un ciclo di studi secondari,</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">o generale completato da un ciclo di studi o di formazione professionale diversi da quelli di cui alla lettera c) e/o dal tirocinio o dalla pratica professionale richiesti in aggiunta a tale ciclo di studi,</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">o tecnico o professionale, completato eventualmente da un ciclo di studi o di formazione professionale di cui al punto i), e/o dal tirocinio o dalla pratica professionale richiesti in aggiunta a tale ciclo di studi;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un diploma che attesta il compimento di</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">o una formazione a livello di insegnamento post-secondario diverso da quello di cui alle lettere d) ed e) di almeno un anno o di una durata equivalente a tempo parziale, di cui una delle condizioni di accesso è, di norma, il completamento del ciclo di studi secondari richiesto per accedere all'insegnamento universitario o superiore ovvero il completamento di una formazione scolastica equivalente al secondo ciclo di studi secondari, nonché la formazione professionale eventualmente richiesta oltre al ciclo di studi post-secondari;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M9\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una formazione o un’istruzione regolamentata oppure, nel caso delle professioni regolamentate, una formazione professionale a struttura particolare, con competenze che vanno oltre quanto previsto al livello b, equivalenti al livello di formazione indicato al punto i), se tale formazione conferisce un analogo livello professionale e prepara a un livello analogo di responsabilità e funzioni, a condizione che detto diploma sia corredato da un certificato dello Stato membro di origine;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un diploma attestante che il titolare ha completato con successo una formazione a livello di insegnamento post-secondario di una durata minima di tre anni e non superiore a quattro anni, o di una durata equivalente a tempo parziale, che può essere espressa anche sottoforma di un numero equivalente di crediti ECTS, presso un’università o un istituto di insegnamento superiore ovvero altro istituto di livello equivalente e, se del caso, il completamento della formazione professionale richiesta in aggiunta al ciclo di studi post-secondari;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un diploma attestante che il titolare ha completato un ciclo di studi post-secondari della durata di almeno quattro anni o di una durata equivalente a tempo parziale, che può essere anche espressa sotto forma di un numero equivalente di crediti ECTS, presso un’università o un istituto di insegnamento superiore ovvero altro istituto di livello equivalente e, se del caso, che ha completato con successo la formazione professionale richiesta in aggiunta al ciclo di studi post-secondari.</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "12": {"label": "Articolo 12", "heading": "Titioli di formazione assimilati", "anchor": "art_12", "frags": [[null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<p class=\"norm\">È assimilato a un titolo di formazione di cui all’articolo 11, anche per quanto riguarda il livello, ogni titolo di formazione o insieme di titoli di formazione rilasciato da un’autorità competente di uno Stato membro che sancisce il completamento con successo di una formazione acquisita nell’Unione, a tempo pieno o parziale, nell’ambito o al di fuori di programmi formali, che è riconosciuta da tale Stato membro come di livello equivalente, e che conferisce al titolare gli stessi diritti di accesso o di esercizio a una professione o prepara al relativo esercizio.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">È altresì assimilata ad un titolo di formazione, alle stesse condizioni del primo comma, ogni qualifica professionale che, pur non rispondendo ai requisiti delle norme legislative, regolamentari o amministrative dello Stato membro d'origine per l'accesso a una professione o il suo esercizio, conferisce al suo titolare diritti acquisiti in virtù di tali disposizioni. Ciò si applica, in particolare, se lo Stato membro d'origine eleva il livello di formazione richiesto per l'ammissione ad una professione e per il suo esercizio, e se una persona che ha seguito una precedente formazione, che non risponde ai requisiti della nuova qualifica, beneficia dei diritti acquisiti in forza delle disposizioni nazionali legislative, regolamentari o amministrative; in tal caso, detta formazione precedente è considerata dallo Stato membro ospitante, ai fini dell'applicazione dell'articolo 13, corrispondente al livello della nuova formazione.</p>"]]}, "13": {"label": "Articolo 13", "heading": "Condizioni del riconoscimento", "anchor": "art_13", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se, in uno Stato membro ospitante, l’accesso a una professione regolamentata o il suo esercizio sono subordinati al possesso di determinate qualifiche professionali, l’autorità competente di tale Stato membro permette l’accesso alla professione e ne consente l’esercizio, alle stesse condizioni previste per i suoi cittadini, ai richiedenti in possesso dell’attestato di competenza o del titolo di formazione di cui all’articolo 11, prescritto da un altro Stato membro per accedere alla stessa professione ed esercitarla sul suo territorio.</div>\n</div>"], [null, "<p class=\"norm\">Gli attestati di competenza o i titoli di formazione sono rilasciati da un’autorità competente di uno Stato membro, designata nel rispetto delle disposizioni legislative, regolamentari o amministrative di detto Stato membro.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’accesso a una professione e il suo esercizio descritti al paragrafo 1 sono consentiti anche ai richiedenti che, nel corso dei precedenti dieci anni, abbiano esercitato a tempo pieno tale professione per un anno, o per una durata complessiva equivalente a tempo parziale, in un altro Stato membro che non regolamenta detta professione e che abbiano uno o più attestati di competenza o uno o più titoli di formazione rilasciati da un altro Stato membro che non regolamenta tale professione.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Gli attestati di competenza e i titoli di formazione soddisfano le seguenti condizioni:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono rilasciati da un’autorità competente di uno Stato membro, designata nel rispetto delle disposizioni legislative, regolamentari o amministrative di detto Stato membro;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attestano la preparazione del titolare all’esercizio della professione in questione.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Tuttavia, l’anno di esperienza professionale di cui al primo comma non può essere richiesto se i titoli di formazione posseduti dal richiedente sanciscono una formazione e un’istruzione regolamentata.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro ospitante accetta il livello attestato ai sensi dell’articolo 11 dallo Stato membro di origine nonché il certificato mediante il quale lo Stato membro di origine attesta che la formazione e l’istruzione regolamentata o la formazione professionale con una struttura particolare di cui all’articolo 11, lettera c), punto ii), è di livello equivalente a quello previsto all’articolo 11, lettera c), punto i).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In deroga ai paragrafi 1 e 2 del presente articolo e all’articolo 14, l’autorità competente dello Stato membro ospitante può rifiutare l’accesso alla professione e l’esercizio della stessa ai titolari di un attestato di competenza classificato a norma dell’articolo 11, lettera a), qualora la qualifica professionale nazionale richiesta per esercitare tale professione sul suo territorio sia classificata a norma dell’articolo 11, lettera e).</div>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Provvedimenti di compensazione", "anchor": "art_14", "frags": [[null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’articolo 13 non impedisce allo Stato membro ospitante di esigere dal richiedente un tirocinio di adattamento non superiore a tre anni o una prova attitudinale se:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la formazione dallo stesso ricevuta riguarda materie sostanzialmente diverse da quelle coperte dal titolo di formazione richiesto nello Stato membro ospitante;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la professione regolamentata nello Stato membro ospitante include una o più attività professionali regolamentate mancanti nella corrispondente professione nello Stato membro di origine del richiedente e la formazione richiesta nello Stato membro ospitante riguarda materie sostanzialmente diverse da quelle oggetto dell’attestato di competenza o del titolo di formazione del richiedente.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se lo Stato membro ospitante ricorre alla possibilità di cui al paragrafo 1, esso lascerà al richiedente la scelta tra tirocinio di adattamento e prova attitudinale.</div>\n</div>"], [null, "<p class=\"norm\">Se uno Stato membro ritiene che, per una determinata professione, sia necessario derogare alla previsione di cui al primo comma che lascia al richiedente la scelta tra tirocinio di adattamento e prova attitudinale, esso ne informa preventivamente gli altri Stati membri e la Commissione, fornendo adeguata giustificazione della deroga.</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<p class=\"norm\">Se la Commissione ritiene che la deroga di cui al secondo comma sia inappropriata o non conforme al diritto dell’Unione, essa adotta, al più tardi entro tre mesi dal ricevimento di tutte le informazioni necessarie, un atto di esecuzione per chiedere allo Stato membro interessato di astenersi dall’adottare la misura prevista. In mancanza di una reazione della Commissione entro il suddetto termine la deroga può essere applicata.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda le professioni il cui esercizio richieda una conoscenza precisa del diritto nazionale e per le quali la prestazione di consulenza e/o assistenza in materia di diritto nazionale costituisca un elemento essenziale e costante dell'attività professionale, lo Stato membro ospitante può, in deroga al principio enunciato nel paragrafo 2, che lascia al richiedente il diritto di scelta, prescrivere un tirocinio di adattamento o una prova attitudinale.</div>\n</div>"], [null, "<p class=\"norm\">\n<span>\n<span class=\"boldface\">►C2</span>\n</span> Questa disposizione si applica anche ai casi previsti dall'articolo 10, lettere b) e c), dall'articolo 10, lettera d) per quanto riguarda i medici e i dentisti, dall'articolo 10, lettera f) qualora il migrante chieda il riconoscimento in un altro Stato membro in cui le pertinenti attività professionali sono esercitate da infermieri, responsabili dell'assistenza generale e per gli infermieri specializzati in possesso di titoli di formazione specialistica, che hanno seguito la formazione<span class=\"boldface\"> ◄ </span> che porta al possesso dei titoli elencati all'allegato V, punto 5.2.2 e dall'articolo 10, lettera g).</p>"], [null, "<p class=\"norm\">Nei casi di cui all'articolo 10, lettera a), lo Stato membro ospitante può prescrivere un tirocinio di adattamento o una prova attitudinale nel caso di attività di lavoratore autonomo o funzioni direttive in una società che richiedono la conoscenza e l'applicazione di specifiche disposizioni nazionali vigenti, a condizione che la conoscenza e l'applicazione di dette disposizioni nazionali siano richieste dalle competenti autorità dello Stato membro ospitante anche per l'accesso alle attività in questione da parte dei propri cittadini.</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<p class=\"norm inline-element\">In deroga al principio enunciato nel paragrafo 2, che lascia al richiedente il diritto di scelta, lo Stato membro ospitante può richiedere un tirocinio di adattamento o una prova attitudinale nel caso di:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un titolare di una delle qualifiche professionali di cui all’articolo 11, lettera a), che abbia presentato domanda di riconoscimento delle proprie qualifiche professionali, se la qualifica professionale nazionale richiesta è classificata a norma dell’articolo 11, lettera c); o</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un titolare di una delle qualifiche professionali di cui all’articolo 11, lettera b), che abbia presentato domanda di riconoscimento delle proprie qualifiche professionali, se la qualifica professionale nazionale richiesta è classificata a norma dell’articolo 11, lettere d) o e).</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Nel caso di un titolare di una qualifica professionale di cui all’articolo 11, lettera a), che abbia presentato domanda di riconoscimento delle proprie qualifiche professionali, se la qualifica professionale nazionale richiesta è classificata a norma dell’articolo 11, lettera d), lo Stato membro ospitante può imporre un tirocinio di adattamento unitamente a una prova attitudinale.</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ai fini dei paragrafi 1 e 5, per «materie sostanzialmente diverse» si intendono quelle la cui conoscenza, le abilità e le competenze acquisite, sono essenziali per l’esercizio della professione, e in relazione alle quali la formazione ricevuta dal migrante presenta significative differenze in termini di contenuto rispetto alla formazione richiesta dallo Stato membro ospitante.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il paragrafo 1 si applica nel rispetto del principio di proporzionalità. In particolare, se lo Stato membro ospitante intende esigere dal richiedente un tirocinio di adattamento o una prova attitudinale, esso deve innanzitutto verificare se le conoscenze, le abilità e le competenze, formalmente convalidate a tal fine da un organismo competente, acquisite dal richiedente stesso nel corso della propria esperienza professionale ovvero mediante apprendimento permanente in un qualsiasi Stato membro o in un paese terzo, siano per loro natura in grado di coprire, in tutto o in parte, le materie sostanzialmente diverse di cui al paragrafo 4.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La decisione di imporre un tirocinio di adattamento o una prova attitudinale è debitamente motivata. In particolare al richiedente sono comunicate le seguenti informazioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il livello di qualifica professionale richiesto nello Stato membro ospitante e il livello di qualifica professionale detenuto dal richiedente secondo la classificazione stabilita dall’articolo 11; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le differenze sostanziali di cui al paragrafo 4 e le ragioni per cui tali differenze non possono essere compensate dalle conoscenze, dalle abilità e dalle competenze acquisite nel corso dell’esperienza professionale ovvero mediante apprendimento permanente formalmente convalidate a tal fine da un organismo competente.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Gli Stati membri garantiscono che un richiedente abbia la possibilità di svolgere la prova attitudinale di cui al paragrafo 1 entro sei mesi dalla decisione iniziale di imporre tale prova al richiedente.</div>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Requisiti in materia di esperienza professionale", "anchor": "art_16", "frags": [[null, "<p class=\"norm\">Se, in uno Stato membro, l'accesso a una delle attività elencate all'allegato IV o il suo esercizio è subordinato al possesso di conoscenze e competenze generali, commerciali o professionali, lo Stato membro riconosce come prova sufficiente di tali conoscenze e competenze l'aver esercitato l'attività considerata in un altro Stato membro. L'attività deve essere esercitata ai sensi degli articoli 17, 18 e 19.</p>"]]}, "17": {"label": "Articolo 17", "heading": "Attività di cui all'elenco I dell'allegato IV", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In caso di attività di cui all'elenco I dell'allegato IV, l'attività deve essere stata precedentemente esercitata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per sei anni consecutivi come lavoratore autonomo o dirigente d'azienda; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per tre anni consecutivi come lavoratore autonomo o dirigente d'azienda, se il beneficiario prova di aver in precedenza ricevuto, per l'attività in questione, una formazione di almeno tre anni sancita da un certificato riconosciuto dallo Stato membro o giudicata del tutto valida da un competente organismo professionale; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per quattro anni consecutivi come lavoratore autonomo o dirigente d'azienda, se il beneficiario prova di aver in precedenza ricevuto, per l'attività in questione, una formazione di almeno due anni sancita da un certificato riconosciuto dallo Stato membro o giudicata del tutto valida da un competente organismo professionale; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per tre anni consecutivi come lavoratore autonomo, se il beneficiario prova di aver esercitato l'attività in questione per almeno cinque anni come lavoratore subordinato; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per cinque anni consecutivi in funzioni direttive, di cui almeno tre anni con mansioni tecniche che implichino la responsabilità di almeno uno dei reparti dell'azienda, se il beneficiario prova di aver in precedenza ricevuto, per l'attività in questione, una formazione di almeno tre anni sancita da un certificato riconosciuto dallo Stato membro o giudicata del tutto valida da un competente organismo professionale.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi di cui alle lettere a) e d) l'attività non deve essere cessata da più di 10 anni alla data di presentazione della documentazione completa dell'interessato all'autorità competente di cui all'articolo 56.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il paragrafo 1, lettera e) non si applica alle attività del gruppo ex 855 (parrucchieri) della nomenclatura ISIC.</div>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Attività di cui all'elenco II dell'allegato IV", "anchor": "art_18", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In caso di attività di cui all'elenco II dell'allegato IV, l'attività in questione deve essere stata precedentemente esercitata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per cinque anni consecutivi come lavoratore autonomo o dirigente d'azienda; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per tre anni consecutivi come lavoratore autonomo o dirigente d'azienda, se il beneficiario prova di aver in precedenza ricevuto, per l'attività in questione, una formazione di almeno tre anni sancita da un certificato riconosciuto dallo Stato membro o giudicata del tutto valida da un competente organismo professionale; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per quattro anni consecutivi come lavoratore autonomo o dirigente d'azienda, se il beneficiario prova di aver in precedenza ricevuto, per l'attività in questione, una formazione di almeno due anni sancita da un certificato riconosciuto dallo Stato membro o giudicata del tutto valida da un competente organismo professionale; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per tre anni consecutivi come lavoratore autonomo o dirigente d'azienda, se il beneficiario prova di aver esercitato l'attività in questione per almeno cinque anni come lavoratore subordinato; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per cinque anni consecutivi come lavoratore subordinato, se il beneficiario prova di aver in precedenza ricevuto, per l'attività in questione, una formazione di almeno tre anni sancita da un certificato riconosciuto dallo Stato membro o giudicata del tutto valida da un competente organismo professionale; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per sei anni consecutivi come lavoratore subordinato, se il beneficiario prova di aver in precedenza ricevuto, per l'attività in questione, una formazione di almeno due anni sancita da un certificato riconosciuto dallo Stato membro o giudicata del tutto valida da un competente organismo professionale.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi di cui alle lettere a) e d), l'attività non deve essere cessata da più di 10 anni alla data di presentazione della documentazione completa dell'interessato all'autorità competente di cui all'articolo 56.</div>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Attività di cui all'elenco III dell'allegato IV", "anchor": "art_19", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In caso di attività di cui all'elenco III dell'allegato IV, l'attività in questione deve essere stata precedentemente esercitata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per tre anni consecutivi come lavoratore autonomo o dirigente d'azienda; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per due anni consecutivi come lavoratore autonomo o dirigente d'azienda, se il beneficiario prova di aver in precedenza ricevuto, per l'attività in questione, una formazione sancita da un certificato riconosciuto dallo Stato membro o giudicata del tutto valida da un competente organismo professionale; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per due anni consecutivi come lavoratore autonomo o dirigente d'azienda se il beneficiario prova di aver in precedenza esercitato l'attività in questione come lavoratore subordinato per almeno tre anni; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per tre anni consecutivi come lavoratore subordinato, se il beneficiario prova di aver in precedenza ricevuto, per l'attività in questione, una formazione sancita da un certificato riconosciuto dallo Stato membro o giudicata del tutto valida da un competente organismo professionale.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi di cui alle lettere a) e c), l'attività non deve essere cessata da più di 10 anni alla data di presentazione della documentazione completa dell'interessato all'autorità competente di cui all'articolo 56.</div>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Adeguamento della lista delle attività di cui all’allegato IV", "anchor": "art_20", "frags": [[null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 57 <span class=\"italics\">quater</span> riguardo all’adeguamento delle liste di attività di cui all’allegato IV soggetti al riconoscimento dell’esperienza professionale ai sensi dell’articolo 16, ai fini dell’aggiornamento o della chiarificazione delle attività elencate all’allegato IV, in particolare per specificarne ulteriormente la portata e tenere debitamente conto degli ultimi sviluppi nel campo della nomenclatura per attività, a condizione che ciò non comporti alcun restringimento dell’ambito di applicazione delle attività collegate alle singole categorie o che non vi sia alcun trasferimento delle attività tra le attuali liste I, II e III dell’allegato IV.</p>"]]}, "21": {"label": "Articolo 21", "heading": "Principio di riconoscimento automatico", "anchor": "art_21", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro riconosce i titoli di formazione di medico, che danno accesso alle attività professionali di medico con formazione di base e di medico specialista, di infermiere responsabile dell'assistenza generale, di dentista, di dentista specialista, di veterinario, di farmacista e di architetto, di cui all'allegato V e rispettivamente ai punti 5.1.1, 5.1.2, 5.2.2, 5.3.2, 5.3.3, 5.4.2, 5.6.2 e 5.7.1, conformi alle condizioni minime di formazione di cui rispettivamente agli articoli 24, 25, 31, 34, 35, 38, 44 e 46, e attribuisce loro, ai fini dell'accesso alle attività professionali e del loro esercizio, gli stessi effetti sul suo territorio che hanno i titoli di formazione che esso rilascia.</div>\n</div>"], [null, "<p class=\"norm\">I titoli di formazione devono essere rilasciati dai competenti organismi degli Stati membri ed essere eventualmente accompagnati dai certificati di cui all'allegato V e rispettivamente ai punti 5.1.1, 5.1.2, 5.2.2, 5.3.2, 5.3.3, 5.4.2, 5.6.2 e 5.7.1.</p>"], [null, "<p class=\"norm\">Le disposizioni del primo e del secondo comma non pregiudicano i diritti acquisiti di cui agli articoli 23, 27, 33, 37, 39 e 49.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro riconosce, ai fini dell'esercizio della medicina generale in qualità di medico generico nel quadro del suo regime di previdenza sociale nazionale, i titoli di formazione di cui all'allegato V, punto 5.1.4 e rilasciati ai cittadini degli Stati membri dagli altri Stati membri ai sensi delle condizioni minime di formazione di cui all'articolo 28.</div>\n</div>"], [null, "<p class=\"norm\">La disposizione del primo comma non pregiudica i diritti acquisiti di cui all'articolo 30.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro riconosce i titoli di formazione di ostetrica, rilasciati ai cittadini degli Stati membri dagli altri Stati membri, elencati all'allegato V, punto 5.5.2, conformi alle condizioni minime di formazione di cui all'articolo 40 e rispondenti alle modalità di cui all'articolo 41, e attribuisce loro, ai fini dell'accesso alle attività professionali e del loro esercizio, gli stessi effetti sul suo territorio che hanno i titoli di formazione che esso rilascia. Questa disposizione non pregiudica i diritti acquisiti di cui agli articoli 23 e 43.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In relazione all’operatività delle farmacie non soggette a restrizioni territoriali, gli Stati membri possono, a titolo di deroga, decidere di non ritenere validi i titoli di formazione di cui al punto 5.6.2 dell’allegato V per l’apertura al pubblico di nuove farmacie. Ai fini dell’applicazione del presente paragrafo sono altresì considerate nuove farmacie quelle aperte da meno di tre anni.</div>\n</div>"], [null, "<p class=\"norm\">Tale deroga non può trovare applicazione in riferimento ai farmacisti, i cui titoli siano già stati riconosciuti dalle autorità competenti dello Stato membro ospitante per altri fini, che abbiano effettivamente esercitato in maniera legale l’attività professionale di farmacista per almeno tre anni consecutivi nello Stato membro stesso.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I titoli di formazione di architetto di cui all'allegato V, punto 5.7.1. oggetto di riconoscimento automatico ai sensi del paragrafo 1, sanciscono un ciclo di formazione iniziata al più presto nel corso dell'anno accademico di riferimento di cui al suddetto allegato.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro subordina l’accesso alle attività professionali di medico, infermiere responsabile dell’assistenza generale, dentista, veterinario, ostetrica e farmacista nonché il relativo esercizio al possesso di uno dei titoli di formazione di cui rispettivamente ai punti 5.1.1, 5.1.2, 5.1.4, 5.2.2, 5.3.2, 5.3.3, 5.4.2, 5.5.2 e 5.6.2 dell’allegato V attestante, se del caso, l’acquisizione nel corso della propria formazione complessiva, da parte del professionista interessato, delle conoscenze, delle abilità e delle competenze di cui all’articolo 24, paragrafo 3, all’articolo 31, paragrafi 6 e 7, all’articolo 34, paragrafo 3, all’articolo 38, paragrafo 3, all’articolo 40, paragrafo 3 e all’articolo 44, paragrafo 3.</div>\n</div>"], [null, "<p class=\"norm\">Al fine di tenere conto del progresso scientifico e tecnologico generalmente riconosciuto, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 57 <span class=\"italics\">quater</span> per aggiornare le conoscenze e le abilità di cui all’articolo 24, paragrafo 3, all’articolo 31, paragrafo 6, all’articolo 34, paragrafo 3, all’articolo 38, paragrafo 3, all’articolo 40, paragrafo 3, all’articolo 44, paragrafo 3, e all’articolo 46, paragrafo 4, in modo da riflettere l’evoluzione del diritto dell’Unione avente implicazioni dirette per i professionisti interessati.</p>"], [null, "<p class=\"norm\">Detti aggiornamenti non devono comportare la modifica di principi legislativi essenziali vigenti negli Stati membri in materia di organizzazione delle professioni per quanto concerne la formazione e le condizioni di accesso delle persone fisiche. Gli aggiornamenti rispettano la responsabilità degli Stati membri per quanto riguarda l’organizzazione dei sistemi di istruzione di cui all’articolo 165, paragrafo 1, del trattato sul funzionamento dell’Unione europea (TFUE).</p>"], [null, "<p class=\"modref\">\n▼M9 —————</p>"]]}, "21a": {"label": "Articolo 21 bis", "heading": "Procedura di notifica", "anchor": "art_21a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro notifica alla Commissione le disposizioni legislative, regolamentari e amministrative adottate in materia di rilascio dei titoli di formazione relativi alle professioni disciplinate dal presente capo.</div>\n</div>"], [null, "<p class=\"norm\">Per quanto riguarda i titoli di formazione di cui alla sezione 8, la notifica ai sensi del primo comma è inoltre trasmessa agli altri Stati membri.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La notifica di cui al paragrafo 1 comprende informazioni in merito alla durata e al contenuto dei programmi di formazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La notifica di cui al paragrafo 1 è trasmessa mediante il sistema IMI.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Al fine di tenere debitamente conto delle evoluzioni legislative e amministrative negli Stati membri e a condizione che le disposizioni legislative, regolamentari e amministrative notificate a norma del paragrafo 1 del presente articolo siano conformi alle condizioni stabilite dal presente capo, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 57 <span class=\"italics\">quater</span> al fine di modificare i punti da 5.1.1 a 5.1.4, 5.2.2, 5.3.2, 5.3.3, 5.4.2, 5.5.2, 5.6.2 e 5.7.1 dell’allegato V, riguardo all’aggiornamento delle denominazioni adottate dagli Stati membri per identificare i titoli di formazione e, se del caso, dell’organismo che rilascia detti titoli, del certificato che li accompagna e del corrispondente titolo professionale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se le disposizioni legislative, regolamentari e amministrative notificate a norma del paragrafo 1 non sono conformi alle condizioni stabilite dal presente capo, la Commissione adotta un atto di esecuzione con cui respinge la modifica richiesta dei punti da 5.1.1 a 5.1.4, 5.2.2, 5.3.2, 5.3.3, 5.4.2, 5.5.2, 5.6.2 o 5.7.1 dell’allegato V.</div>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Disposizioni comuni sulla formazione", "anchor": "art_22", "frags": [[null, "<p class=\"norm\">Per la formazione di cui agli articoli 24, 25, 28, 31, 34, 35, 38, 40, 44 e 46:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli Stati membri possono autorizzare una formazione a tempo parziale alle condizioni previste dalle autorità competenti; queste ultime fanno sì che la durata complessiva, il livello e la qualità di siffatta formazione non siano inferiori a quelli della formazione continua a tempo pieno;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli Stati membri, ciascuno secondo le proprie procedure specifiche, assicurano, favorendo l’aggiornamento professionale continuo, la possibilità, per i professionisti le cui qualifiche rientrano nell’ambito di applicazione del capo III del presente titolo, di aggiornare le rispettive conoscenze, abilità e competenze in modo da mantenere prestazioni professionali sicure ed efficaci nonché tenersi al passo con i progressi della professione.</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<p class=\"norm\">Gli Stati membri comunicano alla Commissione le misure adottate a norma del primo comma, lettera b), entro il 18 gennaio 2016.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "23": {"label": "Articolo 23", "heading": "Diritti acquisiti", "anchor": "art_23", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatti salvi i diritti acquisiti specifici alle professioni interessate, se i titoli di formazione in medicina che danno accesso alle attività professionali di medico con formazione di base e di medico specialista, di infermiere responsabile dell'assistenza generale, di dentista, di dentista specialista, di veterinario, di ostetrica e di farmacista in possesso dei cittadini degli Stati membri non soddisfano l'insieme dei requisiti di formazione di cui agli articoli 24, 25, 31, 34, 35, 38, 40 e 44, ogni Stato membro riconosce come prova sufficiente i titoli di formazione rilasciati da tali Stati membri se tali titoli sanciscono il compimento di una formazione iniziata prima delle date di riferimento di cui all'allegato V, punti 5.1.1, 5.1.2, 5.2.2, 5.3.2, 5.3.3, 5.4.2, 5.5.2 e 5.6.2, se sono accompagnati da un attestato che certifica l'effettivo e lecito esercizio da parte dei loro titolari dell'attività in questione per almeno tre anni consecutivi nei cinque anni precedenti al rilascio dell'attestato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le stesse norme si applicano ai titoli di formazione in medicina che danno accesso alle attività professionali di medico con formazione di base e di medico specialista, di infermiere responsabile dell'assistenza generale, di dentista, di dentista specialista, di veterinario, di ostetrica e di farmacista acquisiti sul territorio della ex Repubblica democratica tedesca, che non soddisfano i requisiti minimi di formazione di cui agli articoli 24, 25, 31, 34, 35, 38, 40 e 44 se tali titoli sanciscono il compimento di una formazione iniziata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prima del 3 ottobre 1990 per i medici con formazione di base, infermieri responsabili dell'assistenza generale, dentisti, dentisti specialisti, veterinari, ostetriche, farmacisti e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prima del 3 aprile 1992 per i medici specialisti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">I titoli di formazione di cui al primo comma consentono l'esercizio delle attività professionali su tutto il territorio della Germania alle stesse condizioni dei titoli di formazione rilasciati dalle competenti autorità tedesche di cui all'allegato V, punti 5.1.1, 5.1.2, 5.2.2, 5.3.2, 5.3.3, 5.4.2, 5.5.2 e 5.6.2.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Fatto salvo l'articolo 37, paragrafo 1, ogni Stato membro riconosce i titoli di formazione in medicina, che danno accesso alle attività professionali di medico con formazione di base e di medico specialista, di infermiere responsabile dell'assistenza generale, di veterinario, di ostetrica, di farmacista e di architetto che sono in possesso di cittadini degli Stati membri e che sono stati rilasciati nell'ex Cecoslovacchia, o per i quali la corrispondente formazione è iniziata, per la Repubblica ceca e la Slovacchia, anteriormente al 1<span class=\"superscript\">o</span> gennaio 1993, qualora le autorità dell'uno o dell'altro Stato membro summenzionato attestino che detti titoli di formazione hanno sul loro territorio la stessa validità giuridica dei titoli che esse rilasciano e, per quanto riguarda gli architetti, la stessa validità giuridica dei titoli menzionati, per detti Stati membri, all'allegato VI, punto 6, per quanto riguarda l'accesso alle, e l'esercizio delle, attività professionali di medico con formazione di base, medico specialista, infermiere responsabile dell'assistenza generale, veterinario, ostetrica e farmacista, relativamente alle attività di cui all'articolo 45, paragrafo 2, e di architetto, relativamente alle attività di cui all'articolo 48.</div>\n</div>"], [null, "<p class=\"norm\">Detto attestato deve essere corredato di un certificato rilasciato dalle medesime autorità, il quale dimostri l'effettivo e lecito esercizio da parte dei cittadini di tali Stati membri, nel territorio di questi, delle attività in questione per almeno tre anni consecutivi nei cinque anni precedenti il rilascio del certificato.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ogni Stato membro riconosce i titoli di formazione in medicina, che danno accesso alle attività professionali di medico con formazione di base e di medico specialista, di infermiere responsabile dell'assistenza generale, di dentista, di dentista specialista, di veterinario, di ostetrica, di farmacista e di architetto che sono in possesso di cittadini degli Stati membri e che sono stati rilasciati nell'ex Unione Sovietica, o per cui la corrispondente formazione è iniziata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per l'Estonia, anteriormente al 20 agosto 1991,</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per la Lettonia, anteriormente al 21 agosto 1991,</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per la Lituania, anteriormente all'11 marzo 1990,</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">qualora le autorità di uno dei tre Stati membri summenzionati attestino che detti titoli hanno sul loro territorio la stessa validità giuridica dei titoli che esse rilasciano e, per quanto riguarda gli architetti, la stessa validità giuridica dei titoli menzionati, per detti Stati membri, all'allegato VI, punto 6, per quanto riguarda l'accesso alle, e l'esercizio delle, attività professionali di medico con formazione di base, medico specialista, infermiere responsabile dell'assistenza generale, dentista, dentista specialista, veterinario, ostetrica e farmacista, relativamente alle attività di cui all'articolo 45, paragrafo 2, e di architetto, relativamente alle attività di cui all'articolo 48.</p>"], [null, "<p class=\"norm\">Detto attestato deve essere corredato di un certificato rilasciato dalle medesime autorità, il quale dimostri l'effettivo e lecito esercizio da parte dei cittadini di tali Stati membri, nel territorio di questi, delle attività in questione per almeno tre anni consecutivi nei cinque anni precedenti il rilascio del certificato.</p>"], [null, "<p class=\"norm\">Per i titoli di formazione di veterinario rilasciati nell'ex Unione Sovietica o per i quali la corrispondente formazione è iniziata, per l'Estonia, anteriormente al 20 agosto 1991, l'attestato di cui al precedente comma deve essere corredato di un certificato rilasciato dalle autorità estoni, il quale dimostri l'effettivo e lecito esercizio da parte dei cittadini di tale Stato membro, nel territorio di questo, delle attività in questione per almeno cinque anni consecutivi nei sette anni precedenti il rilascio del certificato.</p>"], [null, "<p class=\"modref\">\n▼A1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fatto salvo l'articolo 43 <span class=\"italics\">ter</span>, ogni Stato membro riconosce i titoli di formazione in medicina che danno accesso alle attività professionali di medico con formazione di base e di medico specialista, di infermiere responsabile dell'assistenza generale, di dentista, di dentista specialista, di veterinario, di ostetrica, di farmacista e di architetto che sono in possesso di cittadini degli Stati membri e che sono stati rilasciati nell'ex Jugoslavia o per i quali la corrispondente formazione è iniziata</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per la Slovenia, anteriormente al 25 giugno 1991; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per la Croazia, anteriormente all'8 ottobre 1991;</p>\n</div>\n</div>\n<p class=\"norm inline-element\">qualora le autorità degli Stati membri summenzionati attestino che detti titoli hanno sul loro territorio la stessa validità giuridica dei titoli che esse rilasciano e, per quanto riguarda gli architetti, la stessa validità giuridica dei titoli menzionati, per detti Stati membri, all'allegato VI, punto 6, per quanto riguarda l'accesso alle, e l'esercizio delle, attività professionali di medico con formazione di base, medico specialista, infermiere responsabile dell'assistenza generale, dentista, dentista specialista, veterinario, ostetrica e farmacista, relativamente alle attività di cui all'articolo 45, paragrafo 2, e di architetto, relativamente alle attività di cui all'articolo 48.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Detto attestato deve essere corredato di un certificato rilasciato dalle medesime autorità, il quale dimostri l'effettivo e lecito esercizio da parte dei cittadini di tali Stati membri, nel territorio di questi, delle attività in questione per almeno tre anni consecutivi nei cinque anni precedenti il rilascio del certificato.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro riconosce come prova sufficiente per i cittadini dello Stato membro i cui titoli di formazione di medico, d'infermiere responsabile dell'assistenza generale, di dentista, di veterinario, d'ostetrica e di farmacista non corrispondono alle denominazioni che compaiono per tale Stato membro all'allegato V, punti 5.1.1, 5.1.2, 5.1.3, 5.1.4, 5.2.2, 5.3.2, 5.3.3, 5.4.2, 5.5.2 e 5.6.2, i titoli di formazione rilasciati da tali Stati membri se accompagnati da un certificato rilasciato da autorità od organi competenti.</div>\n</div>"], [null, "<p class=\"norm\">Il certificato di cui al primo comma attesta che i titoli di formazione sanciscono il compimento di una formazione ai sensi rispettivamente degli articoli 24, 25, 28, 31, 34, 35, 38, 40 e 44 e sono assimilati dallo Stato membro che li ha rilasciati a quelli le cui denominazioni appaiono all'allegato V, punti 5.1.1, 5.1.2, 5.1.3, 5.1.4, 5.2.2, 5.3.2, 5.3.3, 5.4.2, 5.5.2 e 5.6.2.</p>"]]}, "23a": {"label": "Articolo 23 bis", "heading": "Circostanze specifiche", "anchor": "art_23a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In deroga alla presente direttiva, la Bulgaria può autorizzare le persone in possesso del titolo di фелдшер (feldsher) rilasciato in Bulgaria anteriormente al 31 dicembre 1999 e che esercitavano questa professione nell'ambito del regime nazionale di sicurezza sociale bulgaro alla data del 1<span class=\"superscript\">o</span> gennaio 2000 a continuare a esercitare detta professione, benché la loro attività sia in parte disciplinata dalle disposizioni della presente direttiva riguardanti, rispettivamente, i medici e gli infermieri responsabili dell'assistenza generale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le persone in possesso del titolo bulgaro di фелдшер (feldsher) di cui al paragrafo 1 non hanno diritto al riconoscimento professionale in altri Stati membri in virtù della presente direttiva come medici e infermieri responsabili dell'assistenza generale.</div>\n</div>"]]}, "24": {"label": "Articolo 24", "heading": "Formazione medica di base", "anchor": "art_24", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'ammissione alla formazione medica di base è subordinata al possesso di un diploma o certificato che dia accesso, per tali studi, a istituti universitari.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La formazione medica di base comprende almeno cinque anni di studio complessivi, che possono essere espressi in aggiunta anche in crediti ECTS equivalenti, consistenti in almeno 5 500  ore di insegnamento teorico e pratico svolte presso o sotto la supervisione di un’università.</div>\n</div>"], [null, "<p class=\"norm\">Per i professionisti che hanno iniziato gli studi prima del 1<span class=\"superscript\">o</span> gennaio 1972, il programma di formazione di cui al primo comma può comportare una formazione pratica di livello universitario di sei mesi, effettuata a tempo pieno sotto il controllo delle autorità competenti.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La formazione medica di base garantisce l'acquisizione da parte dell'interessato delle conoscenze e competenze seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguate conoscenze delle scienze sulle quali si fonda la medicina, nonché una buona comprensione dei metodi scientifici, compresi i principi relativi alla misura delle funzioni biologiche, alla valutazione di fatti stabiliti scientificamente e all'analisi dei dati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguate conoscenze della struttura, delle funzioni e del comportamento degli esseri umani, in buona salute e malati, nonché dei rapporti tra l'ambiente fisico e sociale dell'uomo ed il suo stato di salute;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguate conoscenze dei problemi e dei metodi clinici, atte a sviluppare una concezione coerente della natura delle malattie mentali e fisiche, dei tre aspetti della medicina: prevenzione, diagnosi e terapia, nonché della riproduzione umana;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'adeguata esperienza clinica acquisita in ospedale sotto opportuno controllo.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "25": {"label": "Articolo 25", "heading": "Formazione medica specializzata", "anchor": "art_25", "frags": [[null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’ammissione alla formazione medica specialistica è subordinata al completamento e alla convalida di un programma di formazione medica di base ai sensi dell’articolo 24, paragrafo 2, nel corso del quale siano state acquisite le opportune conoscenze di medicina di base.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La formazione medica specializzata comprende un insegnamento teorico e pratico, effettuato in un centro universitario, un centro ospedaliero universitario o, anche, un istituto di cure sanitarie a tal fine autorizzato da autorità od organi competenti.</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri fanno sì che la durata minima della formazione medica specializzata di cui all'allegato V, punto 5.1.3, non sia inferiore alla durata indicata al suddetto punto. La formazione avviene sotto il controllo di autorità od organi competenti e comporta la partecipazione personale del candidato medico specialista all'attività e alle responsabilità dei servizi in questione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La formazione avviene a tempo pieno in luoghi appositi riconosciuti dalle autorità competenti e implica la partecipazione a tutte le attività mediche del dipartimento in cui essa avviene, anche alle guardie, in modo che lo specialista in formazione dedichi alla formazione pratica e teorica tutta la sua attività professionale per tutta la durata della settimana di lavoro e per tutto l'anno, secondo modalità fissate dalle competenti autorità. Di conseguenza i posti vanno adeguatamente retribuiti.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono prevedere nelle legislazioni nazionali esenzioni parziali, per alcune parti dei corsi di formazione medica specialistica, elencati al punto 5.1.3 dell’allegato V, da applicare caso per caso, a condizione che dette parti siano già state seguite in un altro corso di specializzazione figurante nell’elenco di cui al punto 5.1.3 dell’allegato V per il quale il professionista abbia già ottenuto la qualifica professionale in uno Stato membro. Gli Stati membri garantiscono che l’esenzione accordata non superi la metà della durata minima del corso di formazione medica specialistica in questione.</div>\n</div>"], [null, "<p class=\"norm\">Ciascuno Stato membro notifica alla Commissione e agli altri Stati membri la legislazione nazionale applicabile in materia per ognuna delle citate esenzioni parziali.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri subordinano il rilascio di un titolo di formazione medica specializzata al possesso di uno dei titoli di medico con formazione di base di cui all'allegato V, punto 5.1.1.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 57 <span class=\"italics\">quater</span> riguardo all’adattamento dei periodi minimi di formazione di cui al punto 5.1.3 dell’allegato V al livello del progresso scientifico e tecnico.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "26": {"label": "Articolo 26", "heading": "Denominazioni delle formazioni mediche specializzate", "anchor": "art_26", "frags": [[null, "<p class=\"norm\">I titoli di formazione di medico specialista di cui all'articolo 21 sono quelli che, rilasciati da autorità od organi competenti di cui all'allegato V, punto 5.1.2, corrispondono, per la formazione specializzata in questione, alle denominazioni vigenti nei vari Stati membri che compaiono all'allegato V, punto 5.1.3.</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<p class=\"norm\">Al fine di tenere debitamente conto delle modifiche alla legislazione nazionale e al fine di aggiornare la presente direttiva, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 57 <span class=\"italics\">quater</span> riguardo all’inclusione, nel punto 5.1.3 dell’allegato V, di nuove specializzazioni mediche comuni ad almeno i due quinti degli Stati membri.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "27": {"label": "Articolo 27", "heading": "Diritti acquisiti, specifici ai medici specialisti", "anchor": "art_27", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro ospitante può chiedere ai medici specialisti, la cui formazione medica specializzata a tempo parziale era disciplinata da disposizioni legislative, regolamentari e amministrative vigenti alla data del 20 giugno 1975 e che hanno iniziato la loro formazione di specialisti entro il 31 dicembre 1983, che i loro titoli di formazione siano accompagnati da un attestato che certifichi l'effettivo e lecito esercizio da parte loro dell'attività in questione per almeno tre anni consecutivi nei cinque precedenti il rilascio dell'attestato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro riconosce il titolo di medico specialista rilasciato in Spagna ai medici che hanno completato una formazione specializzata prima del 1 gennaio 1995 anche se tale formazione non soddisfa i requisiti minimi di formazione di cui all'articolo 25, se ad esso si accompagna un certificato rilasciato dalle competenti autorità spagnole attestante che l'interessato ha superato la prova di competenza professionale specifica organizzata nel contesto delle misure eccezionali di regolarizzazione di cui al decreto reale 1497/99 al fine di verificare se l'interessato possiede un livello di conoscenze e di competenze comparabile a quello dei medici che possiedono titoli di medico specialista definiti, per la Spagna, all'allegato V, punti 5.1.2 e 5.1.3.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Gli Stati membri riconoscono le qualifiche di medico specialista acquisite in Italia, ed elencate ai punti 5.1.2 e 5.1.3 dell’allegato V, ai medici che abbiano iniziato la loro formazione specialistica dopo il 31 dicembre 1983 e prima del 1<span class=\"superscript\">o</span> gennaio 1991, nonostante la citata formazione non soddisfi tutti i requisiti previsti dall’articolo 25, la qualifica sia corredata di un attestato rilasciato dalla competenti autorità italiane da cui risulti che il medico interessato ha effettivamente e in maniera legale esercitato l’attività di medico specialista in Italia, nella stessa area specialistica in questione, per almeno sette anni consecutivi durante i dieci anni che precedono il conferimento dell’attestato.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro che ha abrogato le disposizioni legislative, regolamentari o amministrative sul rilascio dei titoli di formazione di medico specialista di cui all'allegato V, punti 5.1.2 e 5.1.3, e che ha adottato a favore dei suoi cittadini provvedimenti sui diritti acquisiti, riconosce ai cittadini degli altri Stati membri il diritto di beneficiare delle stesse misure, purché siffatti titoli di formazione siano stati rilasciati prima della data a partire dalla quale lo Stato membro ospitante ha cessato di rilasciare i suoi titoli di formazione per la specializzazione interessata.</div>\n</div>"], [null, "<p class=\"norm\">Le date di abrogazione di queste disposizioni si trovano all'allegato V, punto 5.1.3.</p>"]]}, "28": {"label": "Articolo 28", "heading": "Formazione specifica in medicina generale", "anchor": "art_28", "frags": [[null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’ammissione alla formazione specifica in medicina generale presuppone il completamento e la convalida di un programma di formazione medica di base di cui all’articolo 24, paragrafo 2, nel corso del quale il tirocinante ha acquisito le conoscenze necessarie di medicina di base.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La formazione specifica in medicina generale che fa conseguire titoli di formazione rilasciati entro il 1<span class=\"superscript\">o</span> gennaio 2006 dura almeno due anni a tempo pieno. Per i titoli di formazione rilasciati dopo tale data, dura almeno tre anni a tempo pieno.</div>\n</div>"], [null, "<p class=\"norm\">Se il ciclo di formazione di cui all'articolo 24 implica una formazione pratica dispensata in un centro ospedaliero autorizzato, dotato di attrezzature e servizi adeguati di medicina generale o in seno a un ambulatorio di medicina generale autorizzato o a un centro autorizzato in cui i medici dispensano cure primarie, la durata di tale formazione pratica può essere inclusa, nel limite di un anno, nella durata di cui al primo comma per i titoli di formazione rilasciati a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2006.</p>"], [null, "<p class=\"norm\">È possibile ricorrere alla facoltà di cui al secondo comma solo negli Stati membri in cui la durata della formazione specifica in medicina generale era di due anni alla data del 1<span class=\"superscript\">o</span> gennaio 2001.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La formazione specifica in medicina generale avviene a tempo pieno sotto il controllo delle autorità od organi competenti ed è di natura più pratica che teorica.</div>\n</div>"], [null, "<p class=\"norm\">La formazione pratica è dispensata, da un lato, per almeno sei mesi in un centro ospedaliero autorizzato, dotato di attrezzature e servizi adeguati e, dall'altro, per almeno sei mesi in seno a un ambulatorio di medicina generale autorizzato o a un centro autorizzato in cui i medici dispensano cure primarie.</p>"], [null, "<p class=\"norm\">Essa è collegata ad altri istituti o strutture sanitari che si occupano di medicina generale. Tuttavia, fatti salvi i periodi minimi di cui al secondo comma, la formazione pratica può essere dispensata per un periodo di sei mesi al massimo in altri istituti o strutture sanitarie autorizzati che si occupano di medicina generale.</p>"], [null, "<p class=\"norm\">La formazione implica la partecipazione personale del candidato all'attività professionale e alle responsabilità delle persone con cui lavora.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri subordinano il rilascio del titolo di formazione specifica in medicina generale al possesso di uno dei titoli di medico con formazione di base di cui all'allegato V, punto 5.1.1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono rilasciare i titoli di formazione di cui all'allegato V, punto 5.1.4 a un medico che non ha compiuto la formazione di cui al presente articolo ma ha completato un'altra formazione complementare sancita da un titolo di formazione rilasciato dalle autorità competenti di uno Stato membro. Tuttavia, si possono rilasciare titoli di formazione solo se sanciscono conoscenze di livello qualitativamente equivalente a quello delle conoscenze derivanti dalla formazione di cui al presente articolo.</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri stabiliscono tra l'altro in che misura si possa tener conto della formazione complementare e dell'esperienza professionale acquisita dal richiedente in sostituzione della formazione di cui al presente articolo.</p>"], [null, "<p class=\"norm\">Gli Stati membri possono rilasciare il titolo di formazione di cui all'allegato V, punto 5.1.4 solo se il richiedente ha acquisito un'esperienza in medicina generale di almeno sei mesi in seno a un ambulatorio di medicina generale o a un centro in cui i medici dispensano cure primarie di cui al paragrafo 3.</p>"]]}, "29": {"label": "Articolo 29", "heading": "Esercizio delle attività professionali di medico di medicina generale", "anchor": "art_29", "frags": [[null, "<p class=\"norm\">Nel quadro del suo regime nazionale di previdenza sociale, ogni Stato membro, fatte salve le norme sui diritti acquisiti, subordina l'esercizio dell'attività di medico di medicina generale al possesso di un titolo di formazione di cui all'allegato V, punto 5.1.4.</p>"], [null, "<p class=\"norm\">Gli Stati membri possono esentare da questa condizione le persone in corso di formazione specifica in medicina generale.</p>"]]}, "30": {"label": "Articolo 30", "heading": "Diritti acquisiti, specifici ai medici di medicina generale", "anchor": "art_30", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro stabilisce i diritti acquisiti ma, nel quadro del suo regime nazionale di previdenza sociale, deve ritenere acquisito il diritto di esercitare l'attività di medico di medicina generale, senza il titolo di formazione di cui all'allegato V, punto 5.1.4, a tutti i medici che godono di questo diritto alla data di riferimento indicata al punto sopraindicato in virtù delle norme applicabili alla professione di medico che consentono l'esercizio dell'attività professionale di medico con formazione di base, e che a tale data sono stabiliti sul suo territorio, avendo beneficiato delle disposizioni dell'articolo 21 o dell'articolo 23.</div>\n</div>"], [null, "<p class=\"norm\">Le autorità competenti di ogni Stato membro rilasciano, su richiesta, un certificato attestante il diritto di esercitare l'attività di medico di medicina generale nel quadro del loro regime nazionale di previdenza sociale, senza il titolo di formazione di cui all'allegato V, punto 5.1.4, ai medici che sono titolari di diritti acquisiti ai sensi del primo comma.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro riconosce i certificati di cui al paragrafo 1, secondo comma, rilasciati ai cittadini degli Stati membri dagli altri Stati membri, attribuendo loro gli stessi effetti sul suo territorio che hanno i titoli di formazione che esso rilascia e che permettono l'esercizio dell'attività di medico di medicina generale nel quadro del suo regime nazionale di previdenza sociale.</div>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Formazione d'infermiere responsabile dell'assistenza generale", "anchor": "art_31", "frags": [[null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’ammissione alla formazione di infermiere responsabile dell’assistenza generale è subordinata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al completamento di una formazione scolastica generale di dodici anni sancita da un diploma, attestato o altro titolo rilasciato da autorità od organi competenti di uno Stato membro, o da un certificato attestante il superamento di un esame di livello equivalente che dia accesso all’università o a istituti di insegnamento superiore di un livello riconosciuto come equivalente; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al completamento di una formazione scolastica generale di almeno dieci anni sancita da un diploma, attestato o altro titolo rilasciato da autorità od organi competenti di uno Stato membro, o da un certificato attestante il superamento di un esame di livello equivalente che dia accesso alle scuole professionali o ai programmi di formazione professionale per infermieri.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La formazione d'infermiere responsabile dell'assistenza generale avviene a tempo pieno con un programma che corrisponde almeno a quello di cui all'allegato V, punto 5.2.1.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 57 <span class=\"italics\">quater</span> riguardo alle modifiche dell’elenco di cui al punto 5.2.1 dell’allegato V, al fine di adeguarlo al progresso scientifico e tecnico.</p>"], [null, "<p class=\"norm\">Le modifiche di cui al secondo comma non devono comportare la modifica di principi legislativi essenziali vigenti negli Stati membri in materia di organizzazione delle professioni per quanto concerne la formazione e le condizioni di accesso delle persone fisiche. Esse rispettano la responsabilità degli Stati membri per quanto riguarda l’organizzazione dei sistemi di istruzione di cui all’articolo 165, paragrafo 1, TFUE.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<span>\n<span class=\"boldface\">►M9</span>\n</span> La formazione di infermiere responsabile dell’assistenza generale comprende almeno tre anni di studi complessivi, che possono essere espressi in aggiunta anche in crediti ECTS equivalenti, consistenti in almeno 4 600  ore di insegnamento teorico e clinico in cui l’insegnamento teorico rappresenta almeno un terzo e quello clinico almeno la metà della durata minima della formazione. Gli Stati membri possono accordare esenzioni parziali ai professionisti che hanno acquisito parte della loro formazione nel quadro di altre formazioni di livello almeno equivalente.<span class=\"boldface\"> ◄ </span>\n</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri fanno sì che l'istituzione incaricata della formazione d'infermiere sia responsabile del coordinamento tra l'insegnamento teorico e quello clinico per tutto il programma di studi.</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’istruzione teorica è la parte della formazione di infermiere dalla quale gli aspiranti infermieri apprendono le conoscenze, le abilità e le competenze professionali richieste ai sensi dei paragrafi 6 e 7. La formazione è impartita da insegnanti di scienze infermieristiche e da altro personale competente presso università, istituti di insegnamento superiore di un livello riconosciuto come equivalente o scuole professionali o attraverso programmi di formazione professionale per infermieri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’insegnamento clinico è la parte della formazione di infermiere nella quale gli aspiranti infermieri apprendono, nell’ambito di un gruppo e a diretto contatto con individui e/o collettività sani o malati, a organizzare, dispensare e valutare le necessarie cure infermieristiche globali in base alle conoscenze, alle abilità e alle competenze acquisite. L’aspirante infermiere apprende, oltre che a lavorare come membro di una squadra, a dirigere una squadra e ad organizzare l’assistenza infermieristica globale, anche per quanto concerne l’educazione alla salute per singoli individui e piccoli gruppi in seno alle istituzioni sanitarie o alla collettività.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">L'insegnamento ha luogo in ospedali e altre istituzioni sanitarie e nella collettività, sotto la responsabilità di infermieri insegnanti e con la cooperazione e l'assistenza di altri infermieri qualificati. All'attività dell'insegnamento potrà partecipare anche altro personale qualificato.</p>"], [null, "<p class=\"norm\">I candidati infermieri partecipano alle attività dei servizi in questione nella misura in cui queste contribuiscono alla loro formazione, consentendo loro di apprendere ad assumersi le responsabilità che le cure infermieristiche implicano.</p>"], [null, "<p class=\"modref\">\n▼M18\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La formazione di infermiere responsabile dell'assistenza generale garantisce l'acquisizione da parte del professionista in questione delle conoscenze e abilità seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'estesa conoscenza delle scienze che sono alla base dell'assistenza infermieristica generale, compresa una sufficiente conoscenza dell'organismo, delle funzioni fisiologiche e del comportamento delle persone sane e malate, nonché delle relazioni esistenti tra lo stato di salute e l'ambiente fisico e sociale dell'essere umano;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una conoscenza della natura e dell'etica della professione e dei principi generali riguardanti la salute e l'assistenza infermieristica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'adeguata esperienza clinica; tale esperienza, che dovrebbe essere scelta per il suo valore formativo, dovrebbe essere acquisita sotto il controllo di personale infermieristico qualificato e in luoghi in cui il numero del personale qualificato e l'attrezzatura siano adeguati all'assistenza infermieristica dei pazienti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la capacità di partecipare alla formazione pratica del personale sanitario e un'esperienza di lavoro con tale personale e con altri professionisti del settore sanitario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la capacità di fornire cure infermieristiche personalizzate e di responsabilizzare i pazienti, i parenti e le altre persone interessate in relazione all'autoassistenza e alla necessità di condurre uno stile di vita sano;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la capacità di sviluppare un approccio efficace alla leadership e capacità decisionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conoscenza delle innovazioni tecniche relative ai metodi di assistenza sanitaria e infermieristica.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il titolo di infermiere responsabile dell’assistenza generale sancisce la capacità del professionista in questione di applicare almeno le seguenti competenze, a prescindere dal fatto che la formazione si sia svolta in università, in istituti di insegnamento superiore di un livello riconosciuto come equivalente o in scuole professionali ovvero nell’ambito di programmi di formazione professionale infermieristica:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la competenza di individuare autonomamente le cure infermieristiche necessarie utilizzando le conoscenze teoriche e cliniche attuali nonché di pianificare, organizzare e prestare le cure infermieristiche nel trattamento dei pazienti, sulla base delle conoscenze e delle abilità acquisite ai sensi del paragrafo 6, lettere a), b) e c), in un’ottica di miglioramento della pratica professionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la competenza di lavorare efficacemente con altri operatori del settore sanitario, anche per quanto concerne la partecipazione alla formazione pratica del personale sanitario sulla base delle conoscenze e delle abilità acquisite ai sensi del paragrafo 6, lettere d) ed e);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la competenza di orientare individui, famiglie e gruppi verso stili di vita sani e l’autoterapia, sulla base delle conoscenze e delle abilità acquisite ai sensi del paragrafo 6, lettere a) e b);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la competenza di avviare autonomamente misure immediate per il mantenimento in vita e di intervenire in situazioni di crisi e catastrofi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la competenza di fornire autonomamente consigli, indicazioni e supporto alle persone bisognose di cure e alle loro figure di appoggio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la competenza di garantire autonomamente la qualità delle cure infermieristiche e di valutarle;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la competenza di comunicare in modo esaustivo e professionale e di cooperare con gli esponenti di altre professioni del settore sanitario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la competenza di analizzare la qualità dell’assistenza in un’ottica di miglioramento della propria pratica professionale come infermiere responsabile dell’assistenza generale.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "32": {"label": "Articolo 32", "heading": "Esercizio delle attività professionali d'infermiere responsabile dell'assistenza generale", "anchor": "art_32", "frags": [[null, "<p class=\"norm\">Ai fini della presente direttiva, le attività professionali d'infermiere responsabile dell'assistenza generale sono le attività esercitate a titolo professionale e indicate nell'allegato V, punto 5.2.2.</p>"]]}, "33": {"label": "Articolo 33", "heading": "Diritti acquisiti, specifici agli infermieri responsabili dell'assistenza generale", "anchor": "art_33", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se agli infermieri responsabili dell'assistenza generale si applicano le norme generali sui diritti acquisiti, le attività di cui all'articolo 23 devono comprendere la piena responsabilità della programmazione, organizzazione e somministrazione delle cure infermieristiche ai pazienti.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9 —————</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri riconoscono i titoli di infermiere che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono stati rilasciati in Polonia agli infermieri che abbiano completato anteriormente al 1<span class=\"superscript\">o</span> maggio 2004 la corrispondente formazione che non soddisfa i requisiti minimi di formazione di cui all’articolo 31; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono attestati dal diploma di «licenza di infermiere» ottenuto sulla base di uno speciale programma di rivalorizzazione di cui:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 11 della legge del 20 aprile 2004 che modifica la legge sulle professioni di infermiere e ostetrica e taluni altri atti giuridici (Gazzetta ufficiale della Repubblica di Polonia del 2004 n. 92, pag. 885 e del 2007, n. 176, pag. 1237), e il regolamento del ministro della Sanità dell’11 maggio 2004 sulle condizioni dettagliate riguardanti i corsi impartiti agli infermieri e alle ostetriche, che sono titolari di un certificato di scuola secondaria (esame finale - maturità) e che hanno conseguito un diploma di infermiere e di ostetrica presso un liceo medico o una scuola professionale medica (Gazzetta ufficiale della Repubblica di Polonia del 2004, n. 110, pag. 1170 e del 2010, n. 65, pag. 420), o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dall’articolo 52, paragrafo 3, della legge del 15 luglio 2011 relativa alle professioni di infermiere e ostetrica (Gazzetta ufficiale della Repubblica di Polonia del 2011, n. 174, pag. 1039) e al regolamento del ministro della Sanità del 14 giugno 2012 sulle condizioni dettagliate riguardanti i corsi di istruzione universitaria impartiti agli infermieri e alle ostetriche che sono titolari di un certificato di scuola secondaria (esame finale — maturità) e che hanno conseguito un diploma di infermiere e di ostetrica presso una scuola medica secondaria o un istituto di studi superiori (Gazzetta ufficiale della Repubblica di Polonia del 2012, pag. 770);</p>\n</div>\n</div>\n<p class=\"list\">allo scopo di verificare che gli infermieri interessati siano in possesso di un livello di conoscenza e di competenza paragonabile a quello degli infermieri in possesso delle qualifiche di cui alla lista per la Polonia, al punto 5.2.2 dell’allegato V.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "33a": {"label": "Articolo 33 bis", "heading": "Diritti acquisiti specifici agli infermieri responsabili dell’assistenza generale che hanno completato la formazione in Romania", "anchor": "art_33a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda la qualifica rumena di infermiere responsabile dell’assistenza generale, si applicano solo le disposizioni relative ai diritti acquisiti stabilite al paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nel caso dei cittadini degli Stati membri che hanno completato in Romania una formazione di infermiere responsabile dell’assistenza generale che non soddisfa i requisiti minimi di cui all’articolo 31, gli Stati membri riconoscono come prova sufficiente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">uno qualsiasi dei seguenti titoli di formazione di infermiere responsabile dell’assistenza generale, a condizione che tale titolo sia corredato di un certificato da cui risulti che i cittadini degli Stati membri in questione hanno effettivamente esercitato in maniera legale l’attività di infermiere responsabile dell’assistenza generale in Romania, con piena responsabilità anche per la pianificazione, l’organizzazione e la prestazione delle cure infermieristiche ai pazienti, per un periodo di almeno tre anni consecutivi nel corso dei cinque anni precedenti la data di emissione del certificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">\n<span class=\"italics\">Certificat de competențe profesionale de asistent medical generalist</span> conseguito mediante istruzione post-secondaria presso una <span class=\"italics\">școală postliceală</span>, da cui si evinca che la formazione è iniziata prima del 1<span class=\"superscript\">\n<span class=\"superscript\">o</span>\n</span> gennaio 2007;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">\n<span class=\"italics\">Diplomă de absolvire de asistent medical generalist</span> conseguito a seguito di corso di laurea breve, da cui si evinca che la formazione è iniziata prima del 1<span class=\"superscript\">\n<span class=\"superscript\">o</span>\n</span> ottobre 2003; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">\n<span class=\"italics\">Diplomă de licență de asistent medical generalist</span> conseguito a seguito di corso di laurea specialistica, da cui si evinca che la formazione è iniziata prima del 1<span class=\"superscript\">\n<span class=\"superscript\">o</span>\n</span> ottobre 2003;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">uno qualsiasi dei titoli di formazione elencati alla lettera a), punti ii) e iii), a condizione che tale titolo sia corredato del seguente titolo di formazione ottenuto sulla base di uno speciale programma di rivalorizzazione:</p>\n<p class=\"list\">\n<span class=\"italics\">Diplomă de licență</span> di cui all’articolo 3, paragrafo 2, dell’ordinanza congiunta del ministro dell’Istruzione nazionale e del ministro della Sanità n. 4317/943/2014, dell’11 agosto 2014, sull’approvazione dello speciale programma di rivalorizzazione della formazione iniziale degli infermieri responsabili dell’assistenza generale completata prima del 1<span class=\"superscript\">o</span> gennaio 2007 per chi ha conseguito un diploma di istruzione post-secondaria e di istruzione superiore (Gazzetta ufficiale della Romania n. 624 del 26 agosto 2014), corredato di un supplemento al diploma attestante che lo studente ha completato lo speciale programma di rivalorizzazione; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">uno qualsiasi dei titoli di formazione di livello post-secondario elencati all’articolo 4 dell’ordinanza del ministro dell’Istruzione nazionale n. 5114/2014 sull’approvazione della metodologia per l’organizzazione, lo svolgimento e il completamento dello speciale programma di rivalorizzazione della formazione iniziale degli infermieri responsabili dell’assistenza generale completata prima del 1<span class=\"superscript\">o</span> gennaio 2007 per chi ha conseguito un diploma di istruzione post-secondaria (Gazzetta ufficiale della Romania n. 5 del 6 gennaio 2015), a condizione che tale titolo sia corredato del seguente titolo di formazione ottenuto sulla base di uno speciale programma di rivalorizzazione:</p>\n<p class=\"list\">\n<span class=\"italics\">Certificatul de revalorizare a competențelor profesionale</span> di cui all’articolo 3, paragrafo 1, e all’allegato 3 dell’ordinanza congiunta del ministro dell’Istruzione nazionale e del ministro della Sanità n. 4317/943/2014 e all’articolo 16 dell’ordinanza del ministro dell’Istruzione nazionale n. 5114/2014.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "33b": {"label": "Articolo 33 ter", "heading": "Validità dei diritti acquisiti prima del 3 marzo 2024", "anchor": "art_33b", "frags": [[null, "<p class=\"norm\">Gli Stati membri ospitanti garantiscono la validità del riconoscimento della qualifica rumena di infermiere responsabile dell’assistenza generale concesso a norma degli articoli da 10 a 14 della presente direttiva prima del 3 marzo 2024 per i cittadini degli Stati membri che avevano completato in Romania una formazione di infermiere responsabile dell’assistenza generale e non soddisfacevano i requisiti di cui:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 33 <span class=\"italics\">bis</span> della presente direttiva, nella versione in vigore al 1<span class=\"superscript\">\n<span class=\"superscript\">o</span>\n</span> gennaio 2007, o</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 33 <span class=\"italics\">bis</span> della presente direttiva, modificata dalla direttiva 2013/55/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">5</span>\n).</p>\n</div>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Formazione di dentista di base", "anchor": "art_34", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'ammissione alla formazione di dentista di base presuppone il possesso di un diploma o certificato che dia accesso, per tale studio, a istituti universitari o a istituti superiori di livello riconosciuto equivalente, in uno Stato membro.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La formazione di dentista di base è di almeno cinque anni di studio complessivi come minimo, che possono essere espressi in aggiunta anche in crediti ECTS equivalenti, e consiste in almeno 5 000  ore di insegnamento teorico e pratico a tempo pieno, comprendente quanto meno il programma di cui all’allegato V, punto 5.3.1 e che è dispensato presso un’università, un istituto superiore di livello riconosciuto come equivalente o comunque sotto il controllo di un ateneo.</div>\n</div>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 57 <span class=\"italics\">quater</span> riguardo alla modifica dell’elenco di cui al punto 5.3.1 dell’allegato V al fine di adattarlo al progresso scientifico e tecnico.</p>"], [null, "<p class=\"norm\">Le modifiche di cui al secondo comma non devono comportare la modifica di principi legislativi essenziali vigenti negli Stati membri in materia di organizzazione delle professioni per quanto concerne la formazione e le condizioni di accesso delle persone fisiche. Esse rispettano la responsabilità degli Stati membri per quanto riguarda l’organizzazione dei sistemi di istruzione secondo quanto stabilito dall’articolo 165, paragrafo 1, TFUE.</p>"], [null, "<p class=\"modref\">\n▼M18\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La formazione di dentista di base garantisce l'acquisizione da parte dell'interessato delle conoscenze e abilità seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguate conoscenze delle scienze sulle quali si fonda l'odontoiatria, nonché una buona comprensione dei metodi scientifici e in particolare dei principi relativi alla misura delle funzioni biologiche, alla valutazione di fatti stabiliti scientificamente e all'analisi dei dati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguate conoscenze della costituzione, della fisiologia e del comportamento di persone sane e malate, nonché del modo in cui l'ambiente naturale e sociale influisce sullo stato di salute dell'uomo, nella misura in cui ciò abbia rapporti con l'odontoiatria;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguate conoscenze della struttura e della funzione di denti, bocca, mascelle e dei relativi tessuti, sani e malati, nonché dei loro rapporti con lo stato generale di salute ed il benessere fisico e sociale del paziente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguate conoscenze delle discipline e dei metodi clinici che forniscano un quadro coerente delle anomalie, lesioni e malattie dei denti, della bocca, delle mascelle e dei relativi tessuti, nonché dell'odontoiatria sotto l'aspetto preventivo, diagnostico e terapeutico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'adeguata esperienza clinica acquisita sotto opportuno controllo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'adeguata conoscenza dell'odontoiatria digitale e una buona comprensione del suo uso e della sua applicazione sicura nella pratica.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La formazione di dentista di base conferisce le competenze necessarie per esercitare tutte le attività inerenti alla prevenzione, alla diagnosi e alla cura delle anomalie e delle malattie dei denti, della bocca, delle mascelle e dei relativi tessuti.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "35": {"label": "Articolo 35", "heading": "Formazione di dentista specialista", "anchor": "art_35", "frags": [[null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’ammissione alla formazione di dentista specialista è subordinata al compimento e alla convalida di una formazione di dentista base di cui all’articolo 34 o al possesso degli attestati di cui agli articoli 23 e 37.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La formazione di dentista specialista comprende un insegnamento teorico e pratico dispensato in un centro universitario, in un centro di cura, di insegnamento e di ricerca o, eventualmente, in un istituto di cura abilitato a tal fine dalle autorità od organi competenti.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<p class=\"norm\">I corsi di formazione di dentista specialista a tempo pieno hanno una durata minima di tre anni e si svolgono sotto la supervisione delle autorità o degli organi competenti. Essa richiede la partecipazione personale del dentista candidato alla specializzazione nell’attività e alle responsabilità dell’istituto in questione.</p>"], [null, "<p class=\"modref\">\n▼M9 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri subordinano il rilascio del titolo di formazione di dentista specialista al possesso di un titolo di formazione odontoiatrica di base di cui all'allegato V, punto 5.3.2.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 57 <span class=\"italics\">quater</span> riguardo all’adeguamento al progresso scientifico e tecnico del periodo minimo di formazione di cui al paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Per tenere in debita considerazione i cambiamenti apportati alla legislazione nazionale e al fine di aggiornare la presente direttiva, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 57 <span class=\"italics\">quater</span> riguardo all’inclusione, nell’allegato V, punto 5.3.3, di nuove specializzazioni odontoiatriche comuni ad almeno due quinti degli Stati membri.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "36": {"label": "Articolo 36", "heading": "Esercizio delle attività professionali di dentista", "anchor": "art_36", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ai fini della presente direttiva, le attività professionali di dentista sono quelle definite al paragrafo 3 ed esercitate con i titoli professionali di cui all'allegato V, punto 5.3.2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La professione di dentista si basa sulla formazione dentistica di cui all'articolo 34 ed è una professione specifica e distinta da quella di medico, specializzato o no. L'esercizio dell'attività professionale di dentista presuppone il possesso di un titolo di formazione di cui all'allegato V, punto 5.3.2. I titolari di tale titolo di formazione sono assimilati a coloro ai quali si applicano gli articoli 23 o 37.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri garantiscono che, in generale, ai dentisti sia consentito accedere alle attività di prevenzione, diagnosi e trattamento delle anomalie e malattie dei denti, della bocca, delle mascelle e dei tessuti attigui ed esercitare le stesse nel rispetto delle disposizioni regolamentari e delle regole deontologiche che disciplinano la professione alle date di riferimento di cui all'allegato V, punto 5.3.2.</div>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Diritti acquisiti, specifici dei dentisti", "anchor": "art_37", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro riconosce, ai fini dell'esercizio dell'attività professionale di dentista con i titoli di cui all'allegato V, punto 5.3.2, i titoli di formazione in medicina <span>\n<span class=\"boldface\">►M1</span>\n</span>  rilasciati in Italia, Spagna, Austria, Repubblica ceca, Slovacchia e Romania<span class=\"boldface\"> ◄ </span> a chi ha iniziato la formazione in medicina entro la data di riferimento di cui al suddetto allegato per lo Stato membro interessato, accompagnati da un attestato rilasciato dalle autorità competenti di tale Stato membro.</div>\n</div>"], [null, "<p class=\"norm inline-element\">L'attestato deve certificare il rispetto delle due condizioni che seguono:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tali persone hanno esercitato effettivamente, lecitamente e a titolo principale nel suddetto Stato membro l'attività di cui all'articolo 36, per almeno tre anni consecutivi nel corso dei cinque precedenti il rilascio dell'attestato;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tali persone sono autorizzate a esercitare la suddetta attività alle stesse condizioni dei titolari del titolo di formazione indicato per questo Stato nell'allegato V, punto 5.3.2.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">È dispensato dal requisito della pratica professionale di tre anni, di cui al secondo comma, lettera a), chi abbia portato a termine studi di almeno tre anni, che le autorità competenti dello Stato interessato certificano equivalenti alla formazione di cui all'articolo 34.</p>"], [null, "<p class=\"norm\">Per quanto riguarda la Repubblica ceca e la Slovacchia, i titoli di formazione conseguiti nell'ex Cecoslovacchia sono riconosciuti al pari dei titoli di formazione cechi e slovacchi e alle stesse condizioni stabilite nei commi precedenti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro riconosce i titoli di formazione in medicina rilasciati in Italia a chi ha iniziato la formazione universitaria in medicina dopo il 28 gennaio 1980 e prima del 31 dicembre 1984, accompagnati da un attestato rilasciato dalle competenti autorità italiane.</div>\n</div>"], [null, "<p class=\"norm inline-element\">L'attestato deve certificare il rispetto delle tre condizioni che seguono:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tali persone hanno superato la specifica prova attitudinale organizzata dalle competenti autorità italiane per verificare se possiedono conoscenze e competenze di livello paragonabile a quelle dei possessori del titolo di formazione indicato all'allegato V, punto 5.3.2 per l'Italia;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tali persone hanno esercitato effettivamente, lecitamente e a titolo principale in Italia l'attività di cui all'articolo 36, per almeno tre anni consecutivi nel corso dei cinque precedenti il rilascio dell'attestato;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tali persone sono autorizzate a esercitare o esercitano effettivamente, lecitamente e a titolo principale le attività di cui all'articolo 36 alle stesse condizioni dei possessori del titolo di formazione indicato per l'Italia all'allegato V, punto 5.3.2.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">È dispensato dalla prova attitudinale, di cui al secondo comma, lettera a), chi abbia portato a termine studi di almeno tre anni, che le autorità competenti certificano equivalenti alla formazione di cui all'articolo 34.</p>"], [null, "<p class=\"norm\">Sono equiparati ai predetti soggetti coloro che hanno iniziato la formazione universitaria di medico dopo il 31 dicembre 1984, purché i tre anni di studio sopra citati abbiano avuto inizio entro il 31 dicembre 1994.</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In materia di riconoscimento dei titoli ufficiali di formazione di dentista, gli Stati membri riconoscono detti titoli di formazione a norma dell’articolo 21 se i richiedenti hanno iniziato la propria formazione il o anteriormente al 18 gennaio 2016.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro riconosce i titoli di formazione in medicina rilasciati in Spagna ai professionisti che hanno iniziato la formazione universitaria in medicina tra il 1<span class=\"superscript\">o</span> gennaio 1986 e il 31 dicembre 1997, accompagnati da un attestato rilasciato dalle competenti autorità spagnole.</div>\n</div>"], [null, "<p class=\"norm inline-element\">L’attestato conferma il rispetto delle tre condizioni che seguono:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il professionista interessato ha concluso proficuamente almeno tre anni di studio, certificato dalle competenti autorità spagnole come equivalenti alla formazione di cui all’articolo 34;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il professionista in questione ha esercitato effettivamente, in maniera legale e a titolo principale in Spagna le attività di cui all’articolo 36, per almeno tre anni consecutivi nel corso dei cinque precedenti il rilascio dell’attestato;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il professionista in questione è autorizzato a esercitare o esercita effettivamente, in maniera legale e a titolo principale le attività di cui all’articolo 36 alle stesse condizioni dei titolari del titolo di formazione indicato per la Spagna all’allegato V, punto 5.3.2.</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "38": {"label": "Articolo 38", "heading": "Formazione di veterinario", "anchor": "art_38", "frags": [[null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La formazione di veterinario comprende almeno cinque anni di studi teorici e pratici a tempo pieno, che possono essere in aggiunta anche espressi in crediti ECTS equivalenti, presso un’università, un istituto superiore di livello riconosciuto equivalente o sotto la sorveglianza di un’università, che vertano almeno sul programma di studi di cui all’allegato V, punto 5.4.1.</div>\n</div>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 57 <span class=\"italics\">quater</span> riguardo alla modifica dell’elenco di cui all’allegato V, punto 5.4.1, al fine di adattarlo al progresso scientifico e tecnico.</p>"], [null, "<p class=\"norm\">Le modifiche di cui al secondo comma non possono comportare, per alcuno Stato membro, una qualsiasi modifica dei principi legislativi essenziali vigenti concernenti la struttura delle professioni per quanto riguarda la formazione e le condizioni di accesso per le persone fisiche. Dette modifiche rispettano la responsabilità degli Stati membri in materia di organizzazione dei sistemi di istruzione di cui all’articolo 165, paragrafo 1, TFUE.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L'ammissione alla formazione di veterinario è subordinata al possesso di un diploma o certificato che dia accesso, per tale studio, a istituti universitari o a istituti superiori riconosciuti da uno Stato membro come di livello equivalente ai fini dello studio in questione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M19\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La formazione di veterinario garantisce l’acquisizione da parte del professionista interessato delle conoscenze e abilità seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conoscenze delle scienze sulle quali si fondano le attività di veterinario e della pertinente legislazione dell’UE;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguate conoscenze della struttura, delle funzioni, del comportamento e delle esigenze fisiologiche degli animali, nonché le abilità e le competenze richieste per il loro allevamento, la loro alimentazione, il loro benessere, la loro riproduzione e la loro igiene in generale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le abilità e le competenze cliniche, epidemiologiche e analitiche necessarie ai fini della prevenzione, della diagnosi e delle terapie delle malattie degli animali, come pure ai fini della valutazione e della gestione del dolore, della realizzazione in sicurezza di interventi di chirurgia asettica, di sedazione, anestesia e eutanasia, sia a livello individuale che su gruppi di animali, nonché una conoscenza specifica delle malattie trasmissibili all’uomo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguate conoscenze, abilità e competenze di medicina preventiva, tra cui competenze in materia di biosicurezza, indagini e certificazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguate conoscenze dell’igiene e della tecnologia per ottenere, fabbricare e immettere in commercio i mangimi animali o i prodotti alimentari di origine animale destinati al consumo umano, apportando le abilità e competenze necessarie alla comprensione e spiegazione delle buone prassi in materia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le conoscenze, abilità e competenze necessarie all’utilizzo responsabile e ragionato dei prodotti medicinali veterinari, al fine di trattare gli animali e garantire la sicurezza della catena alimentare e la protezione dell’ambiente.</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conoscenze e comprensione adeguate del concetto «One Health», comprese le abilità e le competenze per la sua applicazione e integrazione nella sanità pubblica veterinaria;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conoscenza dell’organizzazione e della gestione di un’impresa veterinaria, compresa la gestione di uno studio veterinario e gli aspetti economici della salute animale; adeguate conoscenze, abilità e competenze in materia di interazione interpersonale e interprofessionale, comunicazione, lavoro di squadra e collaborazione multidisciplinare;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguate conoscenze della gestione dei dati, delle tecnologie dell’informazione e delle tecnologie digitali e abilità e le competenze necessarie per la loro applicazione pratica in ambito veterinario.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "39": {"label": "Articolo 39", "heading": "Diritti acquisiti, specifici ai veterinari", "anchor": "art_39", "frags": [[null, "<p class=\"norm\">Fatto salvo l'articolo 23, paragrafo 4, per i cittadini degli Stati membri i cui titoli di formazione di veterinario sono stati rilasciati in Estonia o per i quali la corrispondente formazione è iniziata in tale Stato anteriormente al 1<span class=\"superscript\">o</span> maggio 2004, gli Stati membri riconoscono detti titoli di formazione di veterinario se sono corredati di un certificato che dimostri l'effettivo e lecito esercizio da parte dei cittadini di tale Stato membro, nel territorio di questo, delle attività in questione per almeno cinque anni consecutivi nei sette anni precedenti il rilascio del certificato.</p>"]]}, "40": {"label": "Articolo 40", "heading": "Formazione di ostetrica", "anchor": "art_40", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La formazione di ostetrica comprende almeno una delle formazioni che seguono:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una formazione specifica a tempo pieno di ostetrica di almeno 3 anni di studi teorici e pratici (possibilità I) vertente almeno sul programma di cui all'allegato V, punto 5.5.1,</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una formazione specifica a tempo pieno di ostetrica di 18 mesi (possibilità II), vertente almeno sul programma di cui all'allegato V, punto 5.5.1 le cui materie non siano comprese in un insegnamento equivalente per la formazione di infermiere responsabile dell'assistenza generale.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri fanno sì che l'ente incaricato della formazione delle ostetriche sia responsabile del coordinamento tra teoria e pratica per tutto il programma di studi.</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 57 <span class=\"italics\">quater</span> riguardo alla modifica della lista di cui all’allegato V, punto 5.5.1, al fine di adattarlo al progresso scientifico e tecnico.</p>"], [null, "<p class=\"norm\">Le modifiche di cui al terzo comma non possono comportare, per alcuno Stato membro, una qualsiasi modifica dei principi legislativi essenziali vigenti concernenti la struttura delle professioni per quanto riguarda la formazione e le condizioni di accesso per le persone fisiche. Dette modifiche rispettano la responsabilità degli Stati membri in materia di organizzazione dei sistemi di istruzione nei termini di cui all’articolo 165, paragrafo 1, TFUE.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’ammissione alla formazione in ostetricia è subordinato a una delle condizioni che seguono:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">compimento di almeno dodici anni di istruzione scolastica generale o possesso di un certificato che attesti il superamento di un esame, di livello equivalente, per l’ammissione a una scuola di ostetricia per il percorso I;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">possesso di un titolo di formazione d’infermiere responsabile dell’assistenza generale di cui all’allegato V, punto 5.2.2, per il percorso II.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La formazione in ostetricia dà la garanzia che il professionista in questione ha acquisito le conoscenze e le abilità seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conoscenza dettagliata delle scienze che sono alla base delle attività di ostetrica/o, in particolare delle scienze ostetriche, dell’ostetricia e della ginecologia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conoscenza adeguata della deontologia della professione e della legislazione pertinente ai fini dell’esercizio della professione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conoscenza adeguata di nozioni di medicina generale (funzioni biologiche, anatomia e fisiologia) e di farmacologia nel settore dell’ostetricia e per quanto riguarda il neonato, nonché conoscenza dei nessi esistenti tra lo stato di salute e l’ambiente fisico e sociale dell’essere umano e del proprio comportamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esperienza clinica adeguata acquisita presso istituzioni approvate per cui l’ostetrica/o è in grado in modo indipendente e sotto la propria responsabilità, per quanto necessario e a esclusione del quadro patologico, di gestire l’assistenza prenatale, condurre il parto e le sue conseguenze in istituzioni approvate e controllare travaglio e nascita, assistenza postnatale e rianimazione neonatale in attesa dell’intervento di un medico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">comprensione adeguata della formazione del personale sanitario ed esperienza della collaborazione con tale personale.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "41": {"label": "Articolo 41", "heading": "Modalità del riconoscimento dei titoli di formazione di ostetrica", "anchor": "art_41", "frags": [[null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I titoli di formazione di ostetrica di cui all’allegato V, punto 5.5.2, beneficiano del riconoscimento automatico ai sensi dell’articolo 21 se soddisfano uno dei seguenti requisiti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una formazione a tempo pieno in ostetricia di almeno tre anni, che possono essere anche espressi, in aggiunta, in crediti ECTS equivalenti, consistente in almeno 4 600  ore di formazione teorica e pratica, di cui almeno un terzo della durata minima in pratica clinica diretta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una formazione a tempo pieno in ostetricia di almeno due anni che possono essere anche espressi, in aggiunta, in crediti ECTS equivalenti, consistente in almeno 3 600  ore, subordinata al possesso di un titolo di formazione d’infermiere responsabile dell’assistenza generale di cui all’allegato V, punto 5.2.2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una formazione a tempo pieno in ostetricia di almeno 18 mesi, che possono anche essere espressi in aggiunta in crediti ECTS equivalenti, consistente in almeno 3 000  ore, subordinata al possesso di un titolo di formazione d’infermiere responsabile dell’assistenza generale di cui all’allegato V, punto 5.2.2 e seguita da una pratica professionale di un anno per la quale sia rilasciato un attestato ai sensi del paragrafo 2.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L'attestato di cui al paragrafo 1 è rilasciato dalle autorità competenti dello Stato membro d'origine e certifica che il titolare, dopo l'acquisizione del titolo di formazione di ostetrica, ha esercitato in modo soddisfacente, in un ospedale o in un istituto di cure sanitarie a tal fine autorizzato, tutte le attività di ostetrica per il periodo corrispondente.</div>\n</div>"]]}, "42": {"label": "Articolo 42", "heading": "Esercizio delle attività professionali di ostetrica", "anchor": "art_42", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le disposizioni della presente sezione si applicano alle attività di ostetrica come definite da ciascun Stato membro, fatto salvo il paragrafo 2, ed esercitate con i titoli professionali di cui all'allegato V, punto 5.5.2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri garantiscono che le ostetriche sono autorizzate almeno all'accesso ed all'esercizio delle seguenti attività.</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornire una buona informazione e dare consigli per quanto concerne i problemi della pianificazione familiare;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">accertare la gravidanza e in seguito sorvegliare la gravidanza normale, effettuare gli esami necessari al controllo dell'evoluzione della gravidanza normale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prescrivere o consigliare gli esami necessari per la diagnosi quanto più precoce di gravidanze a rischio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">predisporre programmi di preparazione dei futuri genitori ai loro compiti, assicurare la preparazione completa al parto e fornire consigli in materia di igiene e di alimentazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assistere la partoriente durante il travaglio e sorvegliare lo stato del feto nell'utero con i mezzi clinici e tecnici appropriati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">praticare il parto normale, quando si tratti di presentazione del vertex, compresa, se necessario, l'episiotomia e, in caso di urgenza, praticare il parto nel caso di una presentazione podalica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">individuare nella madre o nel bambino i segni di anomalie che richiedono l'intervento di un medico e assistere quest'ultimo in caso d'intervento; prendere i provvedimenti d'urgenza che si impongono in assenza del medico e, in particolare, l'estrazione manuale della placenta seguita eventualmente dalla revisione uterina manuale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esaminare il neonato e averne cura; prendere ogni iniziativa che s'imponga in caso di necessità e, eventualmente, praticare la rianimazione immediata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assistere la partoriente, sorvegliare il puerperio e dare alla madre tutti i consigli utili affinché possa allevare il neonato nel modo migliore;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">praticare le cure prescritte da un medico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">redigere i necessari rapporti scritti.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "43": {"label": "Articolo 43", "heading": "Diritti acquisiti, specifici alle ostetriche", "anchor": "art_43", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro riconosce come prova sufficiente per i cittadini degli Stati membri i cui titoli di formazione in ostetricia soddisfano tutti i requisiti minimi di formazione di cui all'articolo 40 ma, ai sensi dell'articolo 41, sono riconoscibili solo se accompagnati dall'attestato di pratica professionale di cui al suddetto articolo 41, paragrafo 2, i titoli di formazione rilasciati dagli Stati membri prima della data di riferimento di cui all'allegato V, punto 5.5.2, accompagnati da un attestato che certifichi l'effettivo e lecito esercizio da parte di questi cittadini delle attività in questione per almeno due anni consecutivi nei cinque che precedono il rilascio dell'attestato.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Per i titoli di formazione in ostetricia, gli Stati membri riconoscono automaticamente le qualifiche professionali se il richiedente ha iniziato la formazione prima del 18 gennaio 2016 e i criteri di ammissione prevedevano all’epoca dieci anni di formazione scolastica generale o un livello equivalente, per la possibilità I, oppure ha completato la formazione come infermiere responsabile dell’assistenza generale confermato da un titolo di formazione di cui all’allegato V, punto 5.2.2, prima di iniziare la formazione in ostetricia, nell’ambito della possibilità II.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le condizioni di cui al paragrafo 1 si applicano ai cittadini degli Stati membri i cui titoli di formazione in ostetricia sanciscono una formazione acquisita sul territorio della ex Repubblica democratica tedesca e che soddisfa tutti i requisiti minimi di formazione di cui all'articolo 40 ma, ai sensi dell'articolo 41, sono riconoscibili solo se accompagnati dall'attestato di pratica professionale di cui all'articolo 41, paragrafo 2, se sanciscono una formazione iniziata prima del 3 ottobre 1990.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9 —————</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri riconoscono i titoli di ostetrica/o che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono stati rilasciati in Polonia a ostetriche/i che hanno completato anteriormente al 1<span class=\"superscript\">o</span> maggio 2004 la corrispondente formazione che non soddisfa i requisiti minimi di formazione di cui all’articolo 40; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è sancita dal titolo di «licenza di infermiere» ottenuto sulla base di uno speciale programma di aggiornamento di cui:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 11 della legge del 20 aprile 2004 che modifica la legge sulle professioni di infermiere e ostetrica e taluni altri atti giuridici (Gazzetta ufficiale della Repubblica di Polonia del 2004 n. 92, pag. 885 e del 2007, n. 176, pag. 1237), e al regolamento del ministro della sanità dell’11 maggio 2004 sulle condizioni dettagliate riguardanti i corsi impartiti agli infermieri e alle ostetriche, che sono titolari di un certificato di scuola secondaria (esame finale - maturità) e che hanno conseguito un diploma presso un liceo medico o una scuola professionale medica per l’insegnamento di una professione di infermiere e ostetrica (Gazzetta ufficiale della Repubblica di Polonia del 2004, n. 110, pag. 1170 e del 2010, n. 65, pag. 420), o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 53, paragrafo 3, della legge del 15 luglio 2011 relativa alle professioni di infermiere e ostetrica (Gazzetta ufficiale della Repubblica di Polonia del 2011, n. 174, pag. 1039), e il regolamento del ministro della sanità del 14 giugno 2012 sulle condizioni dettagliate riguardanti i corsi di insegnamento universitario impartiti agli infermieri e alle ostetriche, che sono titolari di un certificato di scuola secondaria (esame finale - maturità) e che hanno conseguito un diploma di infermiere e di ostetrica presso una scuola medica secondaria o un istituto di studi superiori per l’insegnamento di una professione di infermiere e ostetrica (Gazzetta ufficiale della Repubblica di Polonia del 2012, pag. 770),</p>\n</div>\n</div>\n<p class=\"list\">allo scopo di verificare che le ostetriche/i interessate/i sono in possesso di un livello di conoscenze e di competenze paragonabili a quello delle ostetriche/i in possesso delle qualifiche di cui alla lista per la Polonia all’allegato V, punto 5.5.2.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "43a": {"label": "Articolo 43 bis", "heading": "", "anchor": "art_43a", "frags": [[null, "<p class=\"norm\">Per quanto riguarda il titolo rumeno di ostetrica, si applicano solo le seguenti disposizioni relative ai diritti acquisiti.</p>"], [null, "<p class=\"norm\">Per i cittadini degli Stati membri i cui titoli di titoli di ostetrica (asistent medical obstetrică-ginecologie) sono stati rilasciati dalla Romania anteriormente alla data di adesione e la cui formazione non soddisfa i requisiti minimi di formazione di cui all'articolo 40, ogni Stato membro riconosce detti titoli come prova sufficiente ai fini dell'esercizio delle attività di ostetrica se corredati di un attestato il quale dimostri l'effettivo e lecito esercizio da parte dei cittadini di tale Stato membro, nel territorio della Romania, delle attività di ostetrica per un periodo di almeno cinque anni consecutivi nei sette anni precedenti il rilascio del certificato.</p>"]]}, "43b": {"label": "Articolo 43 ter", "heading": "", "anchor": "art_43b", "frags": [[null, "<p class=\"norm\">I diritti acquisiti in ostetricia non si applicano ai seguenti titoli ottenuti in Croazia anteriormente al 1<span class=\"superscript\">o</span> luglio 2013: viša medicinska sestra ginekološko-opstetričkog smjera (infermiere di livello superiore in area ostetrico-ginecologica), medicinska sestra ginekološko-opstetričkog smjera (infermiere in area ostetrico-ginecologica), viša medicinska sestra primaljskog smjera (infermiere di livello superiore con diploma in ostetricia), medicinska sestra primaljskog smjera (infermiere con diploma in ostetricia), ginekološko-opstetrička primalja (ostetrica in area ostetrico-ginecologica) e primalja (ostetrica).</p>"]]}, "44": {"label": "Articolo 44", "heading": "Formazione di farmacista", "anchor": "art_44", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'ammissione alla formazione di farmacista è subordinata al possesso di un diploma o certificato che dia accesso, per tale studio, a istituti universitari o a istituti superiori di livello riconosciuto equivalente, in uno Stato membro.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il titolo di formazione di farmacista sancisce una formazione della durata di almeno cinque anni, che può essere anche espressa in aggiunta in crediti ECTS equivalenti, di cui almeno:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quattro anni d’insegnamento teorico e pratico a tempo pieno in un’università, un istituto superiore di livello riconosciuto equivalente o sotto la sorveglianza di un’università;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">durante o al termine della formazione teorica e pratica, sei mesi di tirocinio in una farmacia aperta al pubblico o in un ospedale sotto la sorveglianza del servizio farmaceutico di quest’ultimo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il programma di formazione a cui si fa riferimento nel presente paragrafo include almeno il programma di cui all’allegato V, punto 5.6.1. Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 57 <span class=\"italics\">quater</span> riguardo alla modifica dell’elenco di cui all’allegato V, punto 5.6.1, al fine di adattarlo al progresso scientifico e tecnico, compresa l’evoluzione della prassi farmacologica.</p>"], [null, "<p class=\"norm\">Le modifiche di cui al secondo comma non devono comportare, per alcuno Stato membro, una qualsiasi modifica dei principi legislativi essenziali vigenti concernenti la struttura delle professioni per quanto riguarda la formazione e le condizioni di accesso per le persone fisiche. Le suddette modifiche rispettano la responsabilità degli Stati membri in materia di organizzazione dei sistemi di istruzione nei termini di cui all’articolo 165, paragrafo 1, TFUE.</p>"], [null, "<p class=\"modref\">\n▼M18\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La formazione di farmacista garantisce l'acquisizione da parte dell'interessato delle conoscenze e abilità seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'adeguata conoscenza dei medicinali e delle sostanze utilizzate per la loro fabbricazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'adeguata conoscenza della tecnologia farmaceutica e del controllo fisico, chimico, biologico e microbiologico dei medicinali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'adeguata conoscenza del metabolismo e degli effetti dei medicinali, nonché dell'azione delle sostanze tossiche e dell'utilizzo dei medicinali stessi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'adeguata conoscenza che consenta di valutare i dati scientifici concernenti i medicinali in modo da potere su tale base fornire le informazioni appropriate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'adeguata conoscenza dei requisiti legali e di altro tipo in materia di esercizio delle attività farmaceutiche;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'adeguata conoscenza della farmacia clinica e dell'assistenza farmaceutica, nonché le competenze relative all'applicazione pratica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conoscenze e abilità adeguate relative alla sanità pubblica e alle sue ripercussioni sulla promozione della salute e sulla gestione delle malattie;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conoscenze e abilità adeguate in materia di collaborazione interdisciplinare, pratica interprofessionale e comunicazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conoscenza adeguata delle tecnologie dell'informazione e della tecnologia digitale e competenze relative all'applicazione pratica.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "45": {"label": "Articolo 45", "heading": "Esercizio delle attività professionali di farmacista", "anchor": "art_45", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ai fini della presente direttiva le attività di farmacista sono quelle il cui accesso ed esercizio è subordinato, in uno o più Stati membri, a condizioni di qualificazione professionale e che sono aperte ai titolari di uno dei titoli di formazione di cui all'allegato V, punto 5.6.2.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri assicurano che i titolari di un titolo di formazione in farmacia, rilasciato da un istituto universitario o da un istituto di livello riconosciuto come equivalente, che soddisfi i requisiti dell’articolo 44, siano autorizzati ad accedere ed esercitare almeno le attività sotto elencate, con l’eventuale riserva, laddove appropriata, di un’esperienza professionale complementare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparazione della forma farmaceutica dei medicinali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fabbricazione e controllo dei medicinali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">controllo dei medicinali in un laboratorio di controllo dei medicinali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">immagazzinamento, conservazione e distribuzione dei medicinali nella fase di commercio all’ingrosso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">approvvigionamento, preparazione, controllo, immagazzinamento, distribuzione e consegna di medicinali sicuri e di qualità nelle farmacie aperte al pubblico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparazione, controllo, immagazzinamento e distribuzione di medicinali sicuri e di qualità negli ospedali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">diffusione di informazioni e di consigli sui medicinali in quanto tali, compreso il loro uso corretto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">segnalazione alle autorità competenti degli effetti indesiderati dei prodotti farmaceutici;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">accompagnamento personalizzato dei pazienti che praticano l’automedicazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contributo a campagne istituzionali di sanità pubblica.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se, in uno Stato membro, l'accesso all'attività di farmacista o il suo esercizio è subordinato al requisito di un'esperienza professionale complementare, oltre al possesso di un titolo di formazione di cui all'allegato V, punto 5.6.2, tale Stato membro riconosce come prova sufficiente al riguardo un attestato rilasciato dalle competenti autorità dello Stato membro d'origine che certifica che l'interessato ha esercitato la suddetta attività nello Stato membro d'origine per un periodo di tempo equivalente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il riconoscimento di cui al paragrafo 3 non interviene per quanto concerne l'esperienza professionale di due anni richiesta dal Granducato del Lussemburgo per il rilascio di una concessione statale di farmacia aperta al pubblico.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se, alla data del 16 settembre 1985, in uno Stato membro esisteva un concorso per esami per scegliere, fra i titolari di cui al paragrafo 2, coloro che diverranno i titolari delle nuove farmacie di cui è stata decisa l'apertura nel quadro di un regime nazionale di ripartizione geografica, tale Stato membro può, in deroga al paragrafo 1, mantenere il concorso e sottoporre ad esso i cittadini degli Stati membri in possesso di uno dei titoli di formazione di farmacista di cui all'allegato V, punto 5.6.2 o che beneficiano del disposto dell'articolo 23.</div>\n</div>"]]}, "46": {"label": "Articolo 46", "heading": "Formazione di architetto", "anchor": "art_46", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La formazione di un architetto prevede:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">almeno cinque anni di studi a tempo pieno, in un’università o un istituto di insegnamento comparabile, sanciti dal superamento di un esame di livello universitario; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non meno di quattro anni di studi a tempo pieno, in un’università o un istituto di insegnamento comparabile, sanciti dal superamento di un esame di livello universitario, accompagnati da un attestato che certifica il completamento di due anni di tirocinio professionale a norma del paragrafo 4.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’architettura deve essere l’elemento principale della formazione di cui al paragrafo 1. Questo insegnamento deve mantenere un equilibrio tra gli aspetti teorici e pratici della formazione in architettura e deve garantire almeno l’acquisizione delle seguenti conoscenze, abilità e competenze:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">capacità di realizzare progetti architettonici che soddisfino le esigenze estetiche e tecniche;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguata conoscenza della storia e delle teorie dell’architettura nonché delle arti, tecnologie e scienze umane a essa attinenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conoscenza delle belle arti in quanto fattori che possono influire sulla qualità della concezione architettonica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguata conoscenza in materia di urbanistica, pianificazione e tecniche applicate nel processo di pianificazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">capacità di cogliere i rapporti tra uomo e opere architettoniche e tra opere architettoniche e il loro ambiente, nonché la capacità di cogliere la necessità di adeguare tra loro opere architettoniche e spazi, in funzione dei bisogni e della misura dell’uomo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">capacità di capire l’importanza della professione e delle funzioni dell’architetto nella società, in particolare elaborando progetti che tengano conto dei fattori sociali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conoscenza dei metodi d’indagine e di preparazione del progetto di costruzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conoscenza dei problemi di concezione strutturale, di costruzione e di ingegneria civile connessi con la progettazione degli edifici;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conoscenza adeguata dei problemi fisici e delle tecnologie nonché della funzione degli edifici, in modo da renderli internamente confortevoli e proteggerli dai fattori climatici, nel contesto dello sviluppo sostenibile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">capacità tecnica che consenta di progettare edifici che rispondano alle esigenze degli utenti, nei limiti imposti dal fattore costo e dai regolamenti in materia di costruzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conoscenza adeguata delle industrie, organizzazioni, regolamentazioni e procedure necessarie per realizzare progetti di edifici e per l’integrazione dei piani nella pianificazione generale.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il numero di anni di insegnamento accademico di cui ai paragrafi 1 e 2 può essere anche espresso in aggiunta in crediti ECTS equivalenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il tirocinio professionale di cui alla lettera b) del paragrafo 1 deve aver luogo solo dopo il completamento dei primi tre anni di insegnamento accademico. Almeno un anno del tirocinio professionale deve fare riferimento alle conoscenze, abilità e competenze acquisite nel corso dell’insegnamento di cui al paragrafo 2. A tal fine il tirocinio professionale deve essere effettuato sotto la supervisione di una persona o di un organismo autorizzato dall’autorità competente dello Stato membro di origine. Detto tirocinio sotto supervisione può aver luogo in ogni paese. Il tirocinio professionale è valutato dall’autorità competente dello Stato membro di origine.</div>\n</div>"]]}, "47": {"label": "Articolo 47", "heading": "Deroghe alle condizioni della formazione di architetto", "anchor": "art_47", "frags": [[null, "<p class=\"norm\">In deroga all’articolo 46, è riconosciuta soddisfacente ai sensi dell’articolo 21 anche: la formazione acquisita nel quadro della promozione sociale o di studi universitari a tempo parziale, che soddisfa i requisiti di cui all’articolo 46, paragrafo 2, sancita dal superamento di un esame in architettura da parte di un professionista che lavori da sette anni o più nel settore dell’architettura sotto il controllo di un architetto o di un ufficio di architetti. L’esame deve essere di livello universitario ed equivalente all’esame finale di cui all’articolo 46, paragrafo 1, lettera b).</p>"]]}, "48": {"label": "Articolo 48", "heading": "Esercizio dell'attività professionale di architetto", "anchor": "art_48", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ai fini della presente direttiva, le attività professionali di architetto sono quelle abitualmente esercitate con il titolo professionale di architetto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Soddisfano i requisiti per esercitare l'attività di architetto, con il titolo professionale di architetto, i cittadini di uno Stato membro autorizzati a usare tale titolo ai sensi di una legge che attribuisce all'autorità competente di uno Stato membro la facoltà di accordarlo a cittadini degli Stati membri particolarmente distintisi per la qualità delle loro realizzazioni in campo architettonico. La natura architettonica delle attività degli interessati è attestata da un certificato rilasciato dal loro Stato membro d'origine.</div>\n</div>"]]}, "49": {"label": "Articolo 49", "heading": "Diritti acquisiti, specifici degli architetti", "anchor": "art_49", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro riconosce <span>\n<span class=\"boldface\">►C2</span>\n</span> i titoli di formazione di architetto, di cui all'allegato VI,<span class=\"boldface\"> ◄ </span> rilasciati dagli altri Stati membri, che sanciscono una formazione iniziata entro l'anno accademico di riferimento di cui al suddetto allegato, anche se non soddisfano i requisiti minimi di cui all'articolo 46, attribuendo loro ai fini dell'accesso alle e dell'esercizio delle attività professionale di architetto, lo stesso effetto sul suo territorio dei titoli di formazione di architetto che esso rilascia.</div>\n</div>"], [null, "<p class=\"norm\">A queste condizioni sono riconosciuti gli attestati delle autorità competenti della Repubblica federale di Germania che sanciscono la rispettiva equivalenza tra i titoli di formazione rilasciati a partire dall'8 maggio 1945 dalle autorità competenti della Repubblica democratica tedesca e quelli di cui al suddetto allegato.</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Il paragrafo 1 si applica inoltre ai titoli di formazione di architetto di cui all’allegato V qualora la formazione abbia avuto inizio prima del 18 gennaio 2016.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fatto salvo il paragrafo 1, ogni Stato membro riconosce, attribuendo loro gli stessi effetti sul suo territorio dei titoli di formazione che esso rilascia per accedere ed esercitare l'attività professionale di architetto, con il titolo professionale di architetto, gli attestati rilasciati ai cittadini degli Stati membri da Stati membri che dispongono di norme per l'accesso e l'esercizio dell'attività di architetto, alle seguenti date:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">1<span class=\"superscript\">o</span> gennaio 1995 per Austria, Finlandia e Svezia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">1<span class=\"superscript\">o</span> gennaio 2004 per la Repubblica ceca, Estonia, Cipro, Lettonia, Lituania, Ungheria, Malta, Polonia, Slovenia e Slovacchia;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M8\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b <span class=\"italics\">bis</span>) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">1° luglio 2013 per la Croazia;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">5 agosto 1987 per gli altri Stati membri.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Gli attestati di cui al primo comma certificano che il loro titolare è stato autorizzato a usare il titolo professionale di architetto entro tale data e, nel quadro di tali norme, ha effettivamente esercitato l'attività in questione per almeno tre anni consecutivi nel corso dei cinque anni precedenti il rilascio dell'attestato.</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini dell’accesso e dell’esercizio delle attività professionali di architetto, ogni Stato membro deve accordare ai titoli di formazione da esso stesso rilasciati gli stessi effetti nel suo territorio: titolo di completamento della formazione vigente al 5 agosto 1985 e iniziata non oltre il 17 gennaio 2014, impartita da «Fachhochschulen» nella Repubblica federale di Germania per un periodo di tre anni, conforme ai requisiti di cui all’articolo 46, paragrafo 2 e idonea all’accesso alle attività di cui all’articolo 48 in detto Stato membro con il titolo professionale di «architetto» purché la formazione sia completata da un periodo di esperienza professionale di 4 anni, nella Repubblica federale di Germania, attestato da un certificato rilasciato dall’autorità competente cui è iscritto l’architetto che desidera beneficiare delle disposizioni della presente direttiva.</div>\n</div>"]]}, "49a": {"label": "Articolo 49 bis", "heading": "Quadro comune di formazione", "anchor": "art_49a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ai fini del presente articolo, per «quadro comune di formazione» si intende l’insieme di conoscenze, abilità e competenze minime necessarie per l’esercizio di una determinata professione. Un quadro comune di formazione non si sostituisce ai programmi nazionali di formazione a meno che uno Stato membro non decida altrimenti a norma della legislazione nazionale. Ai fini dell’accesso e dell’esercizio della professione nello Stato membro che la disciplina, uno Stato membro deve accordare alle qualifiche professionali acquisite sulla base di detto quadro comune gli stessi effetti sul suo territorio riconosciuti ai titoli di formazione da esso stesso rilasciati, a condizione che il predetto quadro sia conforme alle condizioni di cui al paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Un quadro comune di formazione deve rispettare le seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">consente la mobilità fra Stati membri a un numero maggiore di professionisti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la professione cui si applica il quadro comune di formazione è regolamentata o il percorso scolastico e formativo verso di essa è regolamentato in almeno un terzo degli Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’insieme condiviso di conoscenze, abilità e competenze riunisce le conoscenze, le abilità e le competenze richieste nei sistemi di istruzione e formazione applicabili in almeno un terzo degli Stati membri; è irrilevante che le conoscenze, le abilità e le competenze siano state acquisite nell’ambito di un corso di formazione generale presso un’università o un istituto di istruzione superiore ovvero nell’ambito di un corso di formazione professionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il quadro comune di formazione è basato sui livelli dell’EQF, come definito nell’allegato II della raccomandazione del Parlamento europeo e del Consiglio del 23 aprile 2008 sulla costituzione del Quadro europeo delle qualifiche per l’apprendimento permanente (\n<span class=\"superscript\">6</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la professione in questione non è inclusa in un altro quadro di formazione comune e non è soggetta al riconoscimento automatico ai sensi del titolo III, capo III;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il quadro di formazione comune è stato elaborato secondo una procedura equa e trasparente, con la partecipazione anche delle parti interessate pertinenti di Stati membri in cui la professione in oggetto non è regolamentata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il quadro di formazione comune consente ai cittadini di un qualsiasi Stato membro di acquisire la qualifica professionale prevista nell’ambito di detto quadro senza dover essere già membri di una qualsiasi organizzazione professionale o essere iscritti presso detta organizzazione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I rappresentanti delle organizzazioni professionali rappresentative a livello dell’Unione, così come le organizzazioni professionali a livello nazionale o le autorità competenti di almeno un terzo degli Stati membri possono presentare alla Commissione suggerimenti riguardo al quadro di formazione comune conformi alle condizioni di cui al paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 57 <span class=\"italics\">quater</span> per stabilire un quadro di formazione comune per determinate professioni alle condizioni di cui al paragrafo 2 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Uno Stato membro è esentato dall’obbligo di introdurre un quadro di formazione comune di cui al paragrafo 4 nel proprio territorio e dall’obbligo di rilasciare il riconoscimento automatico delle qualifiche professionali acquisito a titolo del quadro di formazione comune ove sia soddisfatta una delle seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel proprio territorio non esistono istituzioni di insegnamento o formazione che offrono formazione per la professione in questione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’introduzione del quadro di formazione comune avrebbe effetti avversi sull’organizzazione del suo sistema di istruzione e formazione professionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sussistono differenze sostanziali tra il quadro di formazione comune e la formazione richiesta nel proprio territorio, con gravi rischi per l’ordine pubblico, la pubblica sicurezza, la salute pubblica o la sicurezza dei destinatari dei servizi o della protezione dell’ambiente.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Entro sei mesi dall’entrata in vigore dell’atto delegato di cui al paragrafo 4, uno Stato membro notifica alla Commissione e agli altri Stati membri:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le qualifiche nazionali e, se del caso, i titoli professionali nazionali conformi al quadro di formazione comune; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ogni ricorso alla deroga di cui al paragrafo 5, corredata di una motivazione in relazione a quali condizioni previste da tale paragrafo siano state soddisfatte. Entro tre mesi la Commissione può richiedere ulteriori chiarimenti se ritiene che lo Stato membro abbia fornito alcuna o insufficiente giustificazione relativamente a una di queste condizioni che devono essere soddisfatte. Lo Stato membro trasmette la replica entro tre mesi dalla richiesta.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La Commissione può adottare un atto di esecuzione con l’elenco delle qualifiche e dei titoli professionali nazionali che fruiscono del riconoscimento automatico ai sensi del quadro di formazione comune adottato a norma del paragrafo 4.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il presente articolo si applica alle specializzazioni di una professione, purché esse riguardino attività professionali il cui accesso ed esercizio è regolamentato negli Stati membri, ove la professione sia già soggetta a riconoscimento automatico ai sensi del capo III del titolo III, ma non la specializzazione di cui trattasi.</div>\n</div>"]]}, "49b": {"label": "Articolo 49 ter", "heading": "Prove di formazione comuni", "anchor": "art_49b", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ai fini del presente articolo, per prova di formazione comune si intende una prova attitudinale standardizzata disponibile tra gli Stati membri partecipanti e riservata ai titolari di determinate qualifiche professionali. Il superamento di detta prova in uno Stato membro abilita il titolare di una determinata qualifica professionale all’esercizio della professione nello Stato membro ospitante alle stesse condizioni applicabili ai possessori di qualifiche professionali acquisite in detto Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ogni prova di formazione comune deve rispettare le seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">consentire la mobilità fra Stati membri a un numero maggiore di professionisti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la professione alla quale si applica la prova di formazione comune è regolamentata o il percorso scolastico e formativo verso di essa è regolamentato in almeno un terzo degli Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la prova di formazione comune è stata preparata seguendo una procedura trasparente, con la partecipazione anche delle parti interessate pertinenti di Stati membri in cui la professione in oggetto non è regolamentata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la prova di formazione comune permette ai cittadini di altri Stati membri di partecipare alla prova stessa e alla sua organizzazione pratica in altri Stati membri, senza dover essere già membri di una qualsiasi organizzazione professionale o essere iscritti presso detta organizzazione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I rappresentanti delle organizzazioni professionali rappresentative a livello dell’Unione, così come le organizzazioni professionali a livello nazionale o le autorità competenti di almeno un terzo degli Stati membri possono presentare alla Commissione suggerimenti riguardo alla prova professionale comune conformi alle condizioni di cui al paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 57 <span class=\"italics\">quater</span> per fissare i contenuti di una prova professionale comune e le condizioni richieste per prendervi parte e superarla.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Uno Stato membro è esentato dall’obbligo di organizzare una prova di formazione comune di cui al paragrafo 4 nel proprio territorio e dall’obbligo di rilasciare il riconoscimento automatico ai professionisti che hanno superato la prova di formazione comune ove sia soddisfatta una delle seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la professione in questione non è regolamentata nel suo territorio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i contenuti della prova di formazione comune non attenuano in misura adeguata gravi rischi per la salute pubblica o la sicurezza dei destinatari dei servizi corrispondenti nel proprio territorio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i contenuti della prova di formazione comune renderebbero l’accesso alla professione significativamente meno attraente rispetto ai requisiti nazionali.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Entro sei mesi dall’entrata in vigore dell’atto delegato di cui al paragrafo 4, uno Stato membro notifica alla Commissione e agli altri Stati membri:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la capacità disponibile per organizzare dette prove; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ogni ricorso alla deroga di cui al paragrafo 5, corredata di una motivazione in relazione a quali condizioni previste da tale paragrafo siano state soddisfatte. Entro tre mesi la Commissione può richiedere ulteriori chiarimenti se ritiene che lo Stato membro abbia fornito alcuna o insufficiente giustificazione relativamente a una di queste condizioni che devono essere soddisfatte. Lo Stato membro trasmette la replica entro tre mesi dalla richiesta.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La Commissione può adottare un atto di esecuzione con l’elenco degli Stati membri in cui devono essere organizzate le prove di formazione comuni a norma del paragrafo 4, la frequenza nel corso dell’anno e altri dettagli necessari all’organizzazione di prove di formazione comuni negli Stati membri.</p>"]]}, "50": {"label": "Articolo 50", "heading": "Documentazione e formalità", "anchor": "art_50", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando deliberano su una richiesta di autorizzazione per esercitare la professione regolamentata interessata ai sensi del presente titolo, le autorità competenti dello Stato membro ospitante possono chiedere i documenti e i certificati di cui all'allegato VII.</div>\n</div>"], [null, "<p class=\"norm\">I documenti di cui all'allegato VII, punto 1, lettere d), e) e f) al momento della loro presentazione non possono risalire a più di tre mesi.</p>"], [null, "<p class=\"norm\">Stati membri, organismi e altre persone giuridiche garantiscono la riservatezza delle informazioni trasmesse.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In caso di dubbio fondato, lo Stato membro ospitante può richiedere alle autorità competenti di uno Stato membro una conferma dell'autenticità degli attestati e dei titoli di formazione rilasciati in questo altro Stato membro nonché, eventualmente, la conferma del fatto che il beneficiario soddisfa, per le professioni di cui al capo III del presente titolo, le condizioni minime di formazione di cui rispettivamente agli articoli 24, 25, 28, 31, 34, 35, 38, 40, 44 e 46.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In caso di dubbio fondato, qualora un titolo di formazione di cui all'articolo 3, paragrafo 1, lettera c) sia stato rilasciato da un'autorità competente di uno Stato membro e riguardi una formazione ricevuta in toto o in parte in un centro legalmente stabilito nel territorio di un altro Stato membro, lo Stato membro ospitante può verificare presso l'autorità competente dello Stato membro di origine:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il programma di formazione del centro che ha impartito la formazione è stato formalmente certificato dal centro di formazione situato nello Stato membro di origine;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il titolo di formazione rilasciato è lo stesso che si sarebbe ottenuto avendo seguito integralmente la formazione nello Stato membro di origine; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se tale titolo conferisce gli stessi diritti professionali nel territorio dello Stato membro di origine.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">In caso di dubbio fondato, lo Stato membro ospitante può chiedere alle autorità competenti di uno Stato membro conferma del fatto che il richiedente non è oggetto di sospensione o di divieto a esercitare detta professione a causa di gravi mancanze professionali o di condanne penali connesse all’esercizio di una delle sue attività professionali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 <span class=\"italics\">ter</span>.  </span>\n<div class=\"norm inline-element\">Lo scambio di informazioni tra le autorità competenti dei diversi Stati membri ai sensi del presente articolo ha luogo attraverso l’IMI.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se per accedere a una professione regolamentata, uno Stato membro ospitante esige dai suoi cittadini di prestare giuramento o una dichiarazione solenne e se la formula del giuramento o della dichiarazione non può essere usata dai cittadini degli altri Stati membri, lo Stato membro ospitante fa sì che gli interessati possano usare una formula adeguata ed equivalente.</div>\n</div>"]]}, "51": {"label": "Articolo 51", "heading": "Procedura di riconoscimento delle qualifiche professionali", "anchor": "art_51", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'autorità competente dello Stato membro ospitante accusa ricevuta della documentazione del richiedente entro un mese a partire dal suo ricevimento e lo informa eventualmente dei documenti mancanti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La procedura d'esame della richiesta di autorizzazione per l'esercizio di una professione regolamentata va completata prima possibile con una decisione debitamente motivata dell'autorità competente dello Stato membro ospitante e comunque entro tre mesi a partire dalla presentazione della documentazione completa da parte dell'interessato. Tuttavia questo termine può essere prorogato di un mese nei casi di cui ai capi I e II del presente titolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La decisione, o la mancata decisione nei termini prescritti, può essere oggetto di un ricorso giurisdizionale di diritto nazionale.</div>\n</div>"]]}, "52": {"label": "Articolo 52", "heading": "Uso del titolo professionale", "anchor": "art_52", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se uno Stato membro ospitante regolamenta l'uso del titolo professionale relativo a un'attività della professione in questione, i cittadini di altri Stati membri autorizzati a esercitare la professione regolamentata in base al titolo III usano il titolo professionale dello Stato membro ospitante che in esso corrisponde a tale professione e ne usano l'eventuale abbreviazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se nello Stato membro ospitante una professione è regolamentata da un'associazione o organizzazione ai sensi dell'articolo 3, paragrafo 2, i cittadini degli Stati membri possono usare il titolo professionale da essa rilasciato, o la sua abbreviazione, solo se possono provare di esserne membri.</div>\n</div>"], [null, "<p class=\"norm\">Se l'associazione o l'organizzazione subordina l'acquisizione della qualità di membro a determinati requisiti essa può farlo solo alle condizioni previste dalla presente direttiva, nei confronti dei cittadini di altri Stati membri che possiedano qualifiche professionali,</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Uno Stato membro non può riservare l’impiego di un titolo professionale ai possessori di specifiche qualifiche professionali se non ha notificato l’associazione o l’organizzazione alla Commissione e agli altri Stati membri a norma dell’articolo 3, paragrafo 2.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "53": {"label": "Articolo 53", "heading": "Conoscenza delle lingue", "anchor": "art_53", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I professionisti che beneficiano del riconoscimento delle qualifiche professionali possiedono la conoscenza delle lingue necessaria all’esercizio della professione nello Stato membro ospitante.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Uno Stato membro assicura che controlli effettuati da un’autorità competente o sotto la sua supervisione per controllare il rispetto dell’obbligo di cui al paragrafo 1 siano limitati alla conoscenza di una lingua ufficiale dello Stato membro ospitante o di una lingua amministrativa dello Stato membro ospitante, a condizione che quest’ultima sia anche una delle lingue ufficiali dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I controlli svolti a norma del paragrafo 2 possono essere imposti se la professione da praticarsi ha ripercussioni sulla sicurezza dei pazienti. I controlli possono essere imposti nei confronti di altre professioni nei casi in cui sussista un serio e concreto dubbio in merito alla sussistenza di una conoscenza sufficiente della lingua di lavoro con riguardo alle attività professionali che il professionista intende svolgere.</div>\n</div>"], [null, "<p class=\"norm\">I controlli possono essere effettuati solo dopo il rilascio di una tessera professionale europea a norma dell’articolo 4 <span class=\"italics\">quinquies</span> o dopo il riconoscimento di una qualifica professionale, a seconda dei casi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il controllo linguistico è proporzionato all’attività da eseguire. Il professionista interessato può presentare ricorso ai sensi del diritto nazionale contro tali controlli.</div>\n</div>"]]}, "54": {"label": "Articolo 54", "heading": "Uso del titolo di studio", "anchor": "art_54", "frags": [[null, "<p class=\"norm\">Fatti salvi gli articoli 7 e 52, lo Stato membro ospitante fa sì che gli interessati abbiano il diritto di usare il titolo di studio dello Stato membro d'origine, ed eventualmente la sua abbreviazione, nella lingua dello Stato membro d'origine. Lo Stato membro ospitante può prescrivere che il titolo sia seguito da nome e luogo dell'istituto o della giuria che l'ha rilasciato. Se il titolo di studio dello Stato membro d'origine può essere confuso con un titolo che, nello Stato membro ospitante, richiede una formazione complementare, non acquisita dal beneficiario, tale Stato membro ospitante può imporre a quest'ultimo di usare il titolo di studio dello Stato membro d'origine in una forma adeguata che esso gli indicherà.</p>"]]}, "55": {"label": "Articolo 55", "heading": "Affiliazione a un regime assicurativo", "anchor": "art_55", "frags": [[null, "<p class=\"norm\">Fatti salvi l'articolo 5, paragrafo 1, e l'articolo 6, primo comma, lettera b), gli Stati membri che, alle persone che hanno acquisito le qualifiche professionali sul loro territorio, chiedono un tirocinio preparatorio e/o un periodo d'esperienza professionale per essere affiliati ad un regime di assicurazione contro le malattie, dispensano da quest'obbligo i titolari di qualifiche professionali di medico e di dentista acquisite in un altro Stato membro.</p>"]]}, "55a": {"label": "Articolo 55 bis", "heading": "Riconoscimento del tirocinio professionale", "anchor": "art_55a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se l’accesso a una professione regolamentata nello Stato membro di origine è subordinata al compimento di un tirocinio professionale, l’autorità competente dello Stato membro di origine, al momento di prendere in esame una richiesta di autorizzazione all’esercizio di una professione regolamentata, riconosce i tirocini professionali effettuati in un altro Stato membro, a condizione che il tirocinio si attenga alle linee guida pubblicate di cui al paragrafo 2, e tiene conto dei tirocini professionali svolti in un paese terzo. Tuttavia, gli Stati membri possono fissare nella legislazione nazionale un limite ragionevole alla durata della parte del tirocinio professionale che può essere svolta all’estero.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il riconoscimento del tirocinio professionale non sostituisce i requisiti previsti per superare un esame al fine di ottenere l’accesso alla professione in questione. Le autorità competenti pubblicano le linee guida sull’organizzazione e il riconoscimento dei tirocini professionali effettuati in un altro Stato membro o in un paese terzo, in particolare sul ruolo del supervisore del tirocinio professionale.</div>\n</div>"]]}, "56": {"label": "Articolo 56", "heading": "Autorità competenti", "anchor": "art_56", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le autorità competenti dello Stato membro ospitante e di quello d'origine collaborano strettamente e si assistono reciprocamente per agevolare l'applicazione della presente direttiva. Essi garantiscono la riservatezza delle informazioni che scambiano.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<span>\n<span class=\"boldface\">►M9</span>\n</span> Le autorità competenti dello Stato membro d’origine e dello Stato membro ospitante si scambiano informazioni concernenti l’azione disciplinare o le sanzioni penali adottate o qualsiasi altra circostanza specifica grave che potrebbero avere conseguenze sull’esercizio delle attività previste dalla presente direttiva, nel rispetto delle norme sulla protezione dei dati personali di cui alle direttive 95/46/CE e 2002/58/CE.<span class=\"boldface\"> ◄ </span>\n</div>\n</div>"], [null, "<p class=\"norm\">Lo Stato membro d'origine esamina la veridicità dei fatti e le sue autorità decidono la natura e la portata delle indagini da svolgere e comunicano allo Stato membro ospitante le conseguenze che traggono dalle informazioni di cui dispongono.</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Ai fini dei paragrafi 1 e 2, le autorità competenti devono utilizzare il sistema IMI.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro designa, entro il 20 ottobre 2007, le autorità e gli organi competenti preposti a rilasciare o ricevere i titoli di formazione, altri documenti o informazioni, nonché quelli autorizzati a ricevere le domande e prendere le decisioni di cui alla presente direttiva e ne informano immediatamente gli altri Stati membri e la Commissione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro designa un coordinatore per le attività delle autorità competenti di cui al paragrafo 1 e ne informa gli altri Stati membri e la Commissione.</div>\n</div>"], [null, "<p class=\"norm inline-element\">I coordinatori hanno i seguenti compiti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">promuovere l’applicazione uniforme della presente direttiva;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">riunire ogni utile informazione per l’applicazione della presente direttiva e in particolare quelle relative alle condizioni d’accesso alle professioni regolamentate negli Stati membri;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esaminare proposte di quadri comuni di formazione e di prove di formazione comuni;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">scambiare informazioni e migliori prassi al fine di ottimizzare il continuo sviluppo professionale negli Stati membri;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">scambiare informazioni e migliori prassi sull’applicazione delle misure compensative di cui all’articolo 14.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Ai fini dello svolgimento del compito di cui alla lettera b) del presente paragrafo, i coordinatori possono sollecitare l’aiuto dei centri di assistenza di cui all’articolo 57 <span class=\"italics\">ter</span>.</p>"]]}, "56a": {"label": "Articolo 56 bis", "heading": "Meccanismo di allerta", "anchor": "art_56a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le autorità competenti di uno Stato membro informano le autorità competenti di tutti gli altri Stati membri circa un professionista al quale le autorità o le autorità giudiziarie nazionali abbiano limitato o vietato, anche solo a titolo temporaneo, l’esercizio totale o parziale sul territorio di detto Stato membro delle seguenti attività professionali:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">medico e medico generico, in possesso di un titolo di formazione di cui all’allegato V, punti 5.1.1 e 5.1.4;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">medico specialista, in possesso di un titolo di cui all’allegato V, punto 5.1.3;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">infermiere responsabile dell’assistenza generale, in possesso di un titolo di formazione di cui all’allegato V, punto 5.2.2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dentista in possesso di un titolo di formazione di cui all’allegato V, punto 5.3.2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dentista specialista in possesso di un titolo di formazione di cui all’allegato V, punto 5.3.3;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">veterinario in possesso di un titolo di formazione di cui all’allegato V, punto 5.4.2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ostetrica in possesso di un titolo di formazione di cui all’allegato V, punto 5.5.2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">farmacista in possesso di un titolo di formazione di cui all’allegato V, punto 5.6.2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">possessori dei certificati di cui all’allegato VII, punto 2, attestanti che il possessore ha completato una formazione che soddisfa i requisiti minimi di cui rispettivamente agli articoli 24, 25, 31, 34, 35, 38, 40 o 44, ma che è iniziata prima delle date di riferimento per i titoli di cui all’allegato V, punti 5.1.3, 5.1.4, 5.2.2, 5.3.2, 5.3.3, 5.4.2, 5.5.2 e 5.6.2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">possessori di attestati di diritti acquisiti di cui agli articoli 23, 27, 29, 33, 33 <span class=\"italics\">bis</span>, 37, 43 e 43 <span class=\"italics\">bis</span>;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altri professionisti che esercitano attività aventi ripercussioni sulla sicurezza dei pazienti, ove il professionista eserciti una professione regolamentata in detto Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">professionisti che esercitano attività relative all’istruzione dei minori, tra cui l’assistenza e l’istruzione della prima infanzia, ove il professionista eserciti una professione regolamentata in detto Stato membro.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le autorità competenti trasmettono le informazioni di cui al paragrafo 1 mediante un’allerta con il sistema IMI entro un termine di tre giorni dalla data di adozione della decisione che limita o vieta l’esercizio totale o parziale dell’attività professionale al professionista in oggetto. Tali informazioni riguardano:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’identità del professionista;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la professione in questione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni circa l’autorità o il giudice nazionale che adotta la decisione sulla limitazione o il divieto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’ambito di applicazione della limitazione o del divieto; nonché</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il periodo durante il quale si applica la limitazione o il divieto.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le autorità competenti di uno Stato membro interessato informano, entro al massimo tre giorni dalla data di adozione della decisione del tribunale, le autorità competenti di tutti gli altri Stati membri, mediante un’allerta con il sistema IMI, circa l’identità dei professionisti che hanno presentato domanda di riconoscimento di una qualifica ai sensi della presente direttiva e che sono stati successivamente giudicati dai tribunali responsabili di aver falsificato le qualifiche professionali in questo contesto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il trattamento dei dati personali ai fini dello scambio di informazioni di cui ai paragrafi 1 e 3 deve essere effettuato nel rispetto delle direttive 95/46/CE e 2002/58/CE. Il trattamento dei dati personali da parte della Commissione deve avvenire nel rispetto del regolamento (CE) n. 45/2001.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le autorità competenti di tutti gli Stati membri sono informate senza indugio circa la scadenza di un divieto o di una restrizione di cui al paragrafo 1. A tal fine, l’autorità competente dello Stato membro che fornisce l’informazione di cui al paragrafo 1 è altresì tenuta a fornire la data di scadenza, così come ogni successiva modifica a tale data.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli Stati membri fanno in modo che i professionisti nei confronti dei quali un messaggio di allerta è inviato ad altri Stati membri siano informati per iscritto, contemporaneamente all’invio, di detta procedura di allerta e possano presentare ricorso ai sensi del diritto nazionale contro tali decisioni, o chiederne la rettifica, e abbiano accesso a mezzi di tutela al fine di compensare eventuali danni causati da allerte ingiustificate inviate ad altri Stati membri, e in tali casi occorre indicare che contro la decisione sull’allerta il professionista ha intentato un ricorso.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">I dati relativi ai messaggi di allerta possono essere trattati all’interno dell’IMI solo fintanto che sono validi. Le allerte sono eliminate entro tre giorni dalla data di adozione della decisione di revoca o dalla scadenza del divieto o della limitazione di cui al paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">La Commissione adotta atti di esecuzione per l’applicazione del sistema di allerta. Tali atti di esecuzione includono disposizioni sulle autorità legittimate a inviare o ricevere allerte e sul ritiro e la conclusione delle allerte, e sulle misure intese a garantire la sicurezza durante il periodo di trattamento. Gli atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 58, paragrafo 2.</div>\n</div>"]]}, "57": {"label": "Articolo 57", "heading": "Accesso centralizzato online alle informazioni", "anchor": "art_57", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri devono garantire che le seguenti informazioni siano disponibili online attraverso i punti di contatto unici, di cui all’articolo 6 della direttiva 2006/123/CE del Parlamento europeo e del Consiglio, del 12 dicembre 2006, relativa ai servizi nel mercato interno (\n<span class=\"superscript\">7</span>\n), e regolarmente aggiornate:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elenco di tutte le professioni regolamentate nello Stato membro, che rechi gli estremi delle autorità competenti per ciascuna professione regolamentata e dei centri di assistenza di cui all’articolo 57 <span class=\"italics\">ter</span>;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elenco delle professioni per le quali è disponibile una tessera professionale europea, il funzionamento di detta tessera, compresi tutti i diritti a carico dei professionisti, e le autorità competenti per il rilascio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elenco di tutte le professioni per le quali lo Stato membro applica l’articolo 7, paragrafo 4, conformemente alle disposizioni legislative, regolamentari e amministrative nazionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elenco delle formazioni regolamentate e delle formazioni a struttura particolare di cui all’articolo 11, lettera c), punto ii);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i requisiti e le procedure indicati agli articoli 7, 50, 51 e 53 per le professioni regolamentate nello Stato membro, compresi i diritti che i cittadini devono corrispondere e i documenti che devono presentare alle autorità competenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">modalità di ricorso, conformemente alle disposizioni legislative, regolamentari e amministrative nazionali, avverso le decisioni delle autorità competenti adottate ai sensi della presente direttiva.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono affinché le informazioni di cui al paragrafo 1 siano fornite in modo chiaro e comprensibile agli utenti, siano facilmente accessibili mediante connessione remota e per via elettronica e siano aggiornate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri verificano che a qualsiasi richiesta di informazione rivolta ai punti di contatto unici si risponda quanto prima possibile.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri e la Commissione adottano misure di accompagnamento intese a incoraggiare i punti di contatto unici a fornire le informazioni di cui al paragrafo 1 in altre lingue ufficiali dell’Unione europea. Ciò non ha ripercussioni a livello di legislazione degli Stati membri sulle lingue utilizzate nel rispettivo territorio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri collaborano tra loro e con la Commissione ai fini dell’attuazione dei paragrafi 1, 2 e 4.</div>\n</div>"]]}, "57a": {"label": "Articolo 57 bis", "heading": "Procedure per via elettronica", "anchor": "art_57a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri assicurano che tutti i requisiti, le procedure e le formalità relative alle materie disciplinate dalla presente direttiva possano essere espletate, con facilità, mediante connessione remota e per via elettronica attraverso il punto di contatto unico pertinente o la pertinente autorità competente. Ciò non impedisce alle autorità competenti degli Stati membri di richiedere le copie autenticate in una fase successiva, in caso di dubbio fondato e ove strettamente necessario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il paragrafo 1 non si applica allo svolgimento del periodo di adattamento o della prova attitudinale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è giustificata la richiesta da parte degli Stati membri di utilizzare le firme elettroniche avanzate, come indicato all’articolo 2, paragrafo 2, della direttiva 1999/93/CE del Parlamento europeo e del Consiglio, del 13 dicembre 1999, concernente un quadro comunitario per le firme elettroniche (\n<span class=\"superscript\">8</span>\n), per l’espletamento delle procedure di cui al paragrafo 1 del presente articolo, gli Stati membri sono tenuti ad accettare firme elettroniche conformi alla decisione 2009/767/CE della Commissione, del 16 ottobre 2009, che stabilisce misure per facilitare l’uso di procedure per via elettronica mediante i punti di contatto unici di cui alla direttiva 2006/123/CE del Parlamento europeo e del Consiglio relativa ai servizi del mercato interno (\n<span class=\"superscript\">9</span>\n) e a prevedere strumenti tecnici per l’elaborazione dei documenti con le firme elettroniche avanzate in formati definiti nella decisione 2011/130/UE della Commissione, del 25 febbraio 2011, che istituisce requisiti minimi per il trattamento transfrontaliero dei documenti firmati elettronicamente dalle autorità competenti a norma della direttiva 2006/123/CE del Parlamento europeo e del Consiglio relativa ai servizi nel mercato interno (\n<span class=\"superscript\">10</span>\n).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Tutte le procedure sono eseguite a norma dell’articolo 8 della direttiva 2006/123/CE relativa ai punti di contatto unici. I limiti temporali procedurali di cui all’articolo 7, paragrafo 4 e all’articolo 51 della presente direttiva iniziano a decorrere dal momento in cui un cittadino presenta una richiesta o un documento mancante presso un punto di contatto unico o direttamente alla pertinente autorità competente. Qualsiasi richiesta di copie autenticate di cui al paragrafo 1 del presente articolo non è considerata come una richiesta di documenti mancanti.</div>\n</div>"]]}, "57b": {"label": "Articolo 57 ter", "heading": "Centri di assistenza", "anchor": "art_57b", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro designa, al più tardi il 18 gennaio 2016, un centro di assistenza incaricato di fornire ai cittadini, nonché ai centri di assistenza degli altri Stati membri l’assistenza necessaria in materia di riconoscimento delle qualifiche professionali interessate dalla presente direttiva, incluse le informazioni sulla legislazione nazionale che disciplina le professioni e l’esercizio delle stesse, sulla legislazione sociale ed eventualmente sul codice deontologico.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I centri di assistenza degli Stati membri ospitanti sono tenuti ad assistere i cittadini che esercitano i diritti loro conferiti dalla presente direttiva, eventualmente in collaborazione con il centro di assistenza dello Stato membro d’origine nonché con le autorità competenti e i punti di contatto unici nello Stato membro ospitante.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Tutte le autorità competenti dello Stato membro d’origine o ospitante devono prestare piena collaborazione al centro di assistenza dello Stato membro ospitante e, se del caso, dello Stato membro d’origine e trasmettere tutte le informazioni pertinenti su singoli casi ai centri di assistenza negli Stati membri ospitanti che ne fanno richiesta e fatte salve le disposizioni in materia di protezione dei dati conformemente alle direttive 95/46/CE e 2002/58/CE.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Su richiesta della Commissione i centri di assistenza informano quest’ultima sull’esito delle domande che essa sta trattando, entro due mesi dal ricevimento della richiesta.</div>\n</div>"]]}, "57c": {"label": "Articolo 57 quater", "heading": "Esercizio della delega", "anchor": "art_57c", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui all’articolo 3, paragrafo 2, terzo comma, all’articolo 20, all’articolo 21, paragrafo 6, secondo comma, all’articolo 21 <span class=\"italics\">bis</span>, paragrafo 4, all’articolo 25, paragrafo 5, all’articolo 26, secondo comma, all’articolo 31, paragrafo 2, secondo comma, all’articolo 34, paragrafo 2, secondo comma, all’articolo 35, paragrafi 4 e 5, all’articolo 38, paragrafo 1, secondo comma, all’articolo 40, paragrafo 1, terzo comma, all’articolo 44, paragrafo 2, secondo comma, all’articolo 49 <span class=\"italics\">bis</span>, paragrafo 4 e all’articolo 49 <span class=\"italics\">ter</span>, paragrafo 4, è conferito alla Commissione per un periodo di cinque anni a decorrere dal 17 gennaio 2014. La Commissione elabora una relazione sulla delega di potere al più tardi nove mesi prima della scadenza del periodo di cinque anni. La delega di potere è tacitamente prorogata per periodi di identica durata, a meno che il Parlamento europeo o il Consiglio non si oppongano a tale proroga al più tardi tre mesi prima della scadenza di ciascun periodo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui all’articolo 3, paragrafo 2, terzo comma, all’articolo 20, all’articolo 21, paragrafo 6, secondo comma, all’articolo 21 <span class=\"italics\">bis</span>, paragrafo 4, all’articolo 25, paragrafo 5, all’articolo 26, secondo comma, all’articolo 31, paragrafo 2, secondo comma, all’articolo 34, paragrafo 2, secondo comma, all’articolo 35, paragrafi 4 e 5, all’articolo 38, paragrafo 1, terzo comma, all’articolo 40, paragrafo 1, secondo comma, all’articolo 44, paragrafo 2, secondo comma, all’articolo 49 <span class=\"italics\">bis</span>, paragrafo 4 e all’articolo 49 <span class=\"italics\">ter</span>, paragrafo 4, può essere revocato in qualsiasi momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega di potere ivi specificata. Gli effetti della decisione decorrono dal giorno successivo alla pubblicazione della decisione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span> o da una data successiva ivi specificata. Essa non pregiudica la validità degli atti delegati già in vigore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Un atto delegato adottato ai sensi dell’articolo 3, paragrafo 2, terzo comma, dell’articolo 20, dell’articolo 21, paragrafo 6, secondo comma, dell’articolo 21 <span class=\"italics\">bis</span>, paragrafo 4, dell’articolo 25, paragrafo 5, dell’articolo 26, secondo comma, dell’articolo 31, paragrafo 2, secondo comma, dell’articolo 34, paragrafo 2, secondo comma, dell’articolo 35, paragrafi 4 e 5, dell’articolo 38, paragrafo 1, terzo comma, dell’articolo 40, paragrafo 1, secondo comma, dell’articolo 44, paragrafo 2, secondo comma, dell’articolo 49 <span class=\"italics\">bis</span>, paragrafo 4 e dell’articolo 49 <span class=\"italics\">ter</span>, paragrafo 4, entra in vigore solo se né il Parlamento europeo né Consiglio hanno sollevato obiezioni entro il termine di due mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno entrambi informato la Commissione che non intendono sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</div>\n</div>"]]}, "58": {"label": "Articolo 58", "heading": "Procedura di comitato", "anchor": "art_58", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione è assistita da un comitato per il riconoscimento delle qualifiche professionali. Tale comitato è un comitato ai sensi del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo si applica l’articolo 5 del regolamento (UE) n. 182/2011.</div>\n</div>"]]}, "59": {"label": "Articolo 59", "heading": "Trasparenza", "anchor": "art_59", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri notificano alla Commissione un elenco delle professioni regolamentate specificando le attività contemplate da ogni professione, e un elenco delle tipologie regolamentate di istruzione e formazione, e di formazione con una struttura particolare, di cui all’articolo 11, lettera c), punto ii), nel loro territorio entro il 18 gennaio 2016. Le eventuali modifiche apportate a tali elenchi sono notificate senza indebito indugio alla Commissione. La Commissione sviluppa e tiene aggiornata una banca dati accessibile al pubblico delle professioni regolamentate, ivi compresa una descrizione generale delle attività che rientrano in ciascuna professione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Entro il 18 gennaio 2016 gli Stati membri notificano alla Commissione l’elenco delle professioni per le quali è necessaria una verifica preliminare delle qualifiche ai sensi dell’articolo 7, paragrafo 4. Gli Stati membri forniscono alla Commissione una giustificazione specifica per l’inserimento in tale elenco di ciascuna di queste professioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri valutano se i requisiti stabiliti nel loro ordinamento giuridico per limitare l’accesso a una professione o il suo esercizio ai possessori di una specifica qualifica professionale, inclusi l’impiego di titoli professionali e le attività professionali autorizzate in base a tale titolo, indicati all’articolo come «requisiti», sono compatibili con i seguenti principi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i requisiti non devono essere direttamente o indirettamente discriminatori sulla base della nazionalità o del luogo di residenza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i requisiti devono essere giustificati da un motivo imperativo di interesse generale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i requisiti devono essere tali da garantire il raggiungimento dell’obiettivo perseguito e non vanno al di là di quanto è necessario per raggiungere tale obiettivo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il paragrafo 1 si applica inoltre alle professioni regolamentate in uno Stato membro da un’associazione o un’organizzazione ai sensi dell’articolo 3, paragrafo 2, e agli eventuali requisiti in materia di adesione a tali organizzazioni o associazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Entro il 18 gennaio 2016, gli Stati membri trasmettono alla Commissione le informazioni sui requisiti che intendono mantenere e sui motivi per ritenere detti requisiti conformi al disposto del paragrafo 3. Gli Stati membri trasmettono informazioni sui requisiti successivamente introdotti e sui motivi per ritenere detti requisiti conformi al paragrafo 3 entro sei mesi dall’adozione della misura.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Entro il 18 gennaio 2016 e successivamente ogni due anni, gli Stati membri presentano una relazione concernente i requisiti che sono stati eliminati o resi meno rigidi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">La Commissione trasmette le relazioni di cui al paragrafo 6 agli altri Stati membri e questi presentano le loro osservazioni entro un termine di sei mesi. Durante questo periodo di sei mesi, la Commissione consulta le parti interessate, compresi i professionisti interessati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">La Commissione presenta una relazione di sintesi, basata sulle informazioni inviate dagli Stati membri, al gruppo di coordinatori istituito con la decisione 2007/172/CE della Commissione, del 19 marzo 2007, che istituisce un gruppo di coordinatori per il riconoscimento delle qualifiche professionali (\n<span class=\"superscript\">11</span>\n), che può formulare osservazioni in merito a detta relazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Alla luce delle osservazioni di cui ai paragrafi 7 e 8, la Commissione presenta, entro il 18 gennaio 2017, le proprie conclusioni definitive al Parlamento europeo e al Consiglio, eventualmente accompagnate da proposte di nuove iniziative.</div>\n</div>"]]}, "60": {"label": "Articolo 60", "heading": "Relazioni", "anchor": "art_60", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">A partire dal 20 ottobre 2007, gli Stati membri trasmettono alla Commissione, ogni due anni, una relazione sull'applicazione del sistema. Oltre a commenti generali, la relazione comprende una rilevazione statistica delle decisioni prese e una descrizione dei principali problemi derivanti dall'applicazione della presente direttiva.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<p class=\"norm\">A partire dal 18 gennaio 2016 la rilevazione statistica delle decisioni prese di cui al primo comma deve contenere informazioni dettagliate sul numero e la tipologia delle decisioni adottate conformemente alla presente direttiva, comprese le tipologie di decisioni in materia di accesso parziale avviate dalle autorità competenti a norma dell’articolo 4 <span class=\"italics\">septies</span>, e una descrizione dei principali problemi derivanti dall’applicazione della presente direttiva.</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Entro il 18 gennaio 2019, e successivamente ogni cinque anni, la Commissione pubblica una relazione sull’attuazione della presente direttiva.</div>\n</div>"], [null, "<p class=\"norm inline-element\">La prima relazione verte in particolare sui nuovi elementi introdotti nella presente direttiva e prenderà in considerazione in particolare i seguenti temi:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il funzionamento della tessera professionale europea;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la modernizzazione delle conoscenze, delle abilità e delle competenze per le professioni di cui al capo III del titolo III, tra cui l’elenco delle competenze di cui all’articolo 31, paragrafo 7;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il funzionamento dei quadri comuni di formazione e delle prove di formazione comuni;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i risultati dello speciale programma di rivalorizzazione previsto dalle disposizioni legislative, regolamentari e amministrative rumene per i titolari di titolo di formazione di cui all’articolo 33 <span class=\"italics\">bis</span>, nonché per i titolari di un titolo di formazione di livello post-secondario, al fine di valutare la necessità di rivedere le attuali disposizioni che disciplinano il regime dei diritti acquisiti applicabili al titolo di formazione rumeno d’infermiere responsabile dell’assistenza generale.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri forniscono tutte le informazioni necessarie per la stesura della relazione.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "61": {"label": "Articolo 61", "heading": "Clausola di deroga", "anchor": "art_61", "frags": [[null, "<p class=\"norm\">Se uno Stato membro incontra forti difficoltà nell'applicare una disposizione della presente direttiva, la Commissione esamina tali difficoltà insieme allo Stato membro interessato.</p>"], [null, "<p class=\"modref\">\n▼M9\n</p>"], [null, "<p class=\"norm\">Eventualmente la Commissione adotta un atto di esecuzione per permettere allo Stato membro interessato di derogare, per un certo periodo, all’applicazione della norma in questione.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "62": {"label": "Articolo 62", "heading": "Abrogazione", "anchor": "art_62", "frags": [[null, "<p class=\"norm\">Le direttive 77/452/CEE, 77/453/CEE, 78/686/CEE, 78/687/CEE, 78/1026/CEE, 78/1027/CEE, 80/154/CEE, 80/155/CEE, 85/384/CEE, 85/432/CEE, 85/433/CEE, 89/48/CEE, 92/51/CEE, 93/16/CEE e 1999/42/CE sono abrogate a decorrere dal 20 ottobre 2007. I riferimenti alle direttive abrogate si intendono fatti alla presente direttiva e sono fatti salvi gli atti adottati sulla base di dette direttive.</p>"]]}, "63": {"label": "Articolo 63", "heading": "Recepimento", "anchor": "art_63", "frags": [[null, "<p class=\"norm\">Gli Stati membri mettono in vigore le disposizioni legislative, regolamentari e amministrative necessarie per conformarsi alla presente direttiva entro il 20 ottobre 2007. Essi ne informano immediatamente la Commissione.</p>"], [null, "<p class=\"norm\">Quando gli Stati membri adottano tali disposizioni, queste contengono un riferimento alla presente direttiva o sono corredate di un siffatto riferimento all'atto della pubblicazione ufficiale. Le modalità di tale riferimento sono decise dagli Stati membri.</p>"]]}, "64": {"label": "Articolo 64", "heading": "Entrata in vigore", "anchor": "art_64", "frags": [[null, "<p class=\"norm\">La presente direttiva entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea.</span>\n</p>"]]}, "65": {"label": "Articolo 65", "heading": "Destinatari", "anchor": "art_65", "frags": [[null, "<p class=\"norm\">Gli Stati membri sono destinatari della presente direttiva.</p>"]]}}, "recitals": {}};